'use client'

import { useCallback, useEffect, useImperativeHandle, useMemo, useState } from 'react'
import { cn } from '@/lib/utils'
import type { PromptAreaProps, PromptAreaHandle } from './types'
import { usePromptArea } from './use-prompt-area'
import { BLUR_DELAY_MS } from './use-prompt-area-events'
import { TriggerPopover } from './trigger-popover'
import { AnimatedPlaceholder } from './animated-placeholder'
import { ImageStrip } from './image-strip'
import { FileStrip } from './file-strip'

/**
 * PromptArea - A lightweight rich text input with trigger support.
 *
 * Uses contentEditable to support inline chips (immutable pills) for
 * mentions, commands, and other triggered tokens. Each trigger character
 * can be configured to show a dropdown or fire a callback.
 *
 * @example
 * ```tsx
 * const [segments, setSegments] = useState<Segment[]>([])
 *
 * <PromptArea
 *   value={segments}
 *   onChange={setSegments}
 *   triggers={[
 *     { char: '@', position: 'any', mode: 'dropdown', onSearch: searchUsers },
 *     { char: '/', position: 'start', mode: 'dropdown', onSearch: searchCommands },
 *     { char: '#', position: 'any', mode: 'dropdown', onSearch: searchTags },
 *   ]}
 *   placeholder="Type a message..."
 *   onSubmit={handleSubmit}
 *   autoGrow
 * />
 * ```
 */
export function PromptArea({
  value,
  onChange,
  triggers,
  placeholder,
  className,
  disabled = false,
  markdown,
  onSubmit,
  onEscape,
  onChipClick,
  onChipAdd,
  onChipDelete,
  onLinkClick,
  onPaste,
  onUndo,
  onRedo,
  minHeight = 80,
  maxHeight,
  autoFocus = false,
  autoGrow = false,
  'aria-label': ariaLabel,
  'data-test-id': dataTestId,
  images = [],
  imagePosition = 'above',
  onImagePaste,
  onImageRemove,
  onImageClick,
  files = [],
  filePosition = 'above',
  onFileRemove,
  onFileClick,
  ref,
}: PromptAreaProps & { ref?: React.Ref<PromptAreaHandle> }) {
  const {
    editorRef,
    activeTrigger,
    suggestions,
    suggestionsLoading,
    suggestionsError,
    selectedSuggestionIndex,
    handleInput,
    handleKeyDown,
    handleClick,
    selectSuggestion,
    dismissTrigger,
    handle,
    triggerRect,
    eventHandlers,
  } = usePromptArea({
    value,
    onChange,
    triggers,
    onSubmit,
    onEscape,
    onChipClick,
    onChipAdd,
    onChipDelete,
    onLinkClick,
    onPaste,
    onUndo,
    onRedo,
    onImagePaste,
    markdown,
  })

  // Expose imperative handle via ref
  useImperativeHandle(ref, () => handle, [handle])

  // Auto-focus on mount
  useEffect(() => {
    if (autoFocus) {
      editorRef.current?.focus()
    }
  }, [autoFocus, editorRef])

  // -----------------------------------------------------------------------
  // Auto-grow: expand on focus/input, shrink on blur
  // -----------------------------------------------------------------------

  const [isFocused, setIsFocused] = useState(false)
  const [editorHeight, setEditorHeight] = useState<number | undefined>(undefined)

  const syncHeight = useCallback(() => {
    const el = editorRef.current
    if (!el) return
    // Temporarily set height to auto so scrollHeight reflects true content height
    el.style.height = 'auto'
    const contentHeight = el.scrollHeight
    el.style.height = `${contentHeight}px`
    setEditorHeight(contentHeight)
  }, [editorRef])

  const handleFocus = useCallback(() => {
    if (!autoGrow) return
    setIsFocused(true)
    syncHeight()
  }, [autoGrow, syncHeight])

  const handleBlurWithShrink = useCallback(() => {
    eventHandlers.onBlur()
    if (!autoGrow) return
    setTimeout(() => {
      const editor = editorRef.current
      if (!editor) return
      // Only shrink if focus truly left the component
      const activeEl = document.activeElement
      if (activeEl && editor.parentElement?.contains(activeEl)) return
      setIsFocused(false)
      setEditorHeight(undefined)
    }, BLUR_DELAY_MS)
  }, [eventHandlers, autoGrow, editorRef])

  const handleInputWithGrow = useCallback(() => {
    handleInput()
    if (autoGrow && isFocused) {
      syncHeight()
    }
  }, [handleInput, autoGrow, isFocused, syncHeight])

  // Re-measure on value changes (chip insertion, undo/redo, programmatic updates)
  useEffect(() => {
    if (autoGrow && isFocused) {
      requestAnimationFrame(() => syncHeight())
    }
  }, [value, autoGrow, isFocused, syncHeight])

  // -----------------------------------------------------------------------
  // Compute editor style
  // -----------------------------------------------------------------------

  const editorStyle = useMemo((): React.CSSProperties => {
    if (!autoGrow) {
      return {
        minHeight: `${minHeight}px`,
        ...(maxHeight ? { maxHeight: `${maxHeight}px`, overflowY: 'auto' as const } : {}),
      }
    }
    return {
      height: isFocused && editorHeight ? `${editorHeight}px` : `${minHeight}px`,
      minHeight: `${minHeight}px`,
      maxHeight: '70dvh',
      overflowY: 'auto',
      transition: 'height 150ms ease-out',
    }
  }, [autoGrow, minHeight, maxHeight, isFocused, editorHeight])

  const isEmpty =
    value.length === 0 || (value.length === 1 && value[0].type === 'text' && value[0].text === '')

  const imageStrip =
    images.length > 0 ? (
      <ImageStrip
        images={images}
        onRemove={onImageRemove}
        onClick={onImageClick}
        className={imagePosition === 'above' ? 'pb-2' : 'pt-2'}
      />
    ) : null

  const fileStrip =
    files.length > 0 ? (
      <FileStrip
        files={files}
        onRemove={onFileRemove}
        onClick={onFileClick}
        className={filePosition === 'above' ? 'pb-2' : 'pt-2'}
      />
    ) : null

  return (
    <div className={cn('prompt-area-container relative', className)}>
      {imagePosition === 'above' && imageStrip}
      {filePosition === 'above' && fileStrip}

      {/* Editor + placeholder wrapper */}
      <div className="relative">
        <div
          ref={editorRef}
          contentEditable={!disabled}
          suppressContentEditableWarning
          role="textbox"
          aria-label={ariaLabel ?? 'Text input'}
          aria-multiline="true"
          aria-disabled={disabled}
          data-test-id={dataTestId}
          className={cn(
            'prompt-area-editor',
            'w-full min-w-0 break-words whitespace-pre-wrap outline-none',
            'text-sm leading-relaxed',
            disabled && 'cursor-not-allowed opacity-50',
          )}
          style={editorStyle}
          onFocus={handleFocus}
          onInput={autoGrow ? handleInputWithGrow : handleInput}
          onKeyDown={handleKeyDown}
          onClick={handleClick}
          onPaste={eventHandlers.onPaste}
          onCopy={eventHandlers.onCopy}
          onCut={eventHandlers.onCut}
          onDrop={eventHandlers.onDrop}
          onDragOver={eventHandlers.onDragOver}
          onCompositionStart={eventHandlers.onCompositionStart}
          onCompositionEnd={eventHandlers.onCompositionEnd}
          onBlur={autoGrow ? handleBlurWithShrink : eventHandlers.onBlur}
        />

        {/* Placeholder overlay */}
        {isEmpty &&
          placeholder &&
          (Array.isArray(placeholder) ? (
            <AnimatedPlaceholder texts={placeholder} />
          ) : (
            <div
              className="text-muted-foreground pointer-events-none absolute top-0 left-0 text-sm leading-relaxed select-none"
              aria-hidden="true">
              {placeholder}
            </div>
          ))}
      </div>

      {filePosition === 'below' && fileStrip}
      {imagePosition === 'below' && imageStrip}

      {/* Trigger suggestion popover */}
      {activeTrigger && activeTrigger.config.mode === 'dropdown' && (
        <TriggerPopover
          suggestions={suggestions}
          loading={suggestionsLoading}
          error={suggestionsError}
          emptyMessage={activeTrigger.config.emptyMessage}
          selectedIndex={selectedSuggestionIndex}
          onSelect={selectSuggestion}
          onDismiss={dismissTrigger}
          triggerRect={triggerRect}
          triggerChar={activeTrigger.config.char}
        />
      )}
    </div>
  )
}

'use client'

import { useEffect, useRef } from 'react'
import { cn } from '@/lib/utils'
import type { TriggerSuggestion } from './types'

type TriggerPopoverProps = {
  suggestions: TriggerSuggestion[]
  loading: boolean
  error?: string | null
  emptyMessage?: string
  selectedIndex: number
  onSelect: (suggestion: TriggerSuggestion) => void
  onDismiss: () => void
  triggerRect: DOMRect | null
  triggerChar: string
}

/**
 * Floating popover that displays trigger suggestions.
 * Positioned relative to the trigger character location in the editor.
 */
export function TriggerPopover({
  suggestions,
  loading,
  error,
  emptyMessage,
  selectedIndex,
  onSelect,
  onDismiss,
  triggerRect,
  triggerChar,
}: TriggerPopoverProps) {
  const popoverRef = useRef<HTMLDivElement>(null)
  const selectedRef = useRef<HTMLButtonElement>(null)

  // Scroll selected item into view
  useEffect(() => {
    selectedRef.current?.scrollIntoView({ block: 'nearest' })
  }, [selectedIndex])

  // Click outside to dismiss
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      const target = e.target
      if (popoverRef.current && target instanceof Node && !popoverRef.current.contains(target)) {
        onDismiss()
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [onDismiss])

  if (!triggerRect) return null
  if (suggestions.length === 0 && !loading && !error && !emptyMessage) return null

  // Position the popover below the trigger character, clamped to viewport
  const popoverMaxWidth = Math.min(320, window.innerWidth - 16)
  const left = Math.min(triggerRect.left, window.innerWidth - popoverMaxWidth - 8)
  const style: React.CSSProperties = {
    position: 'fixed',
    left: `${Math.max(8, left)}px`,
    top: `${triggerRect.bottom + 4}px`,
    zIndex: 50,
    maxWidth: `${popoverMaxWidth}px`,
  }

  return (
    <div
      ref={popoverRef}
      className={cn(
        'max-h-[240px] min-w-[200px] overflow-y-auto',
        'bg-popover rounded-xl border p-2 shadow-md',
        'animate-in fade-in-0 zoom-in-95',
      )}
      style={style}
      role="listbox"
      aria-label={`${triggerChar} suggestions`}>
      {loading ? (
        <div className="text-muted-foreground px-3 py-2 text-sm">Loading suggestions...</div>
      ) : error ? (
        <div className="text-destructive px-3 py-2 text-sm">{error}</div>
      ) : suggestions.length === 0 && emptyMessage ? (
        <div className="text-muted-foreground px-3 py-2 text-sm">{emptyMessage}</div>
      ) : (
        suggestions.map((suggestion, index) => (
          <button
            key={suggestion.value}
            ref={index === selectedIndex ? selectedRef : undefined}
            type="button"
            role="option"
            aria-selected={index === selectedIndex}
            className={cn(
              'text-foreground flex w-full items-start gap-2 rounded-lg px-3 py-2 text-left text-sm',
              'hover:bg-accent cursor-pointer transition-colors',
              index === selectedIndex && 'bg-accent',
            )}
            onMouseDown={(e) => {
              e.preventDefault() // Prevent blur on the editor
              onSelect(suggestion)
            }}>
            {suggestion.icon && <span className="mt-0.5 shrink-0">{suggestion.icon}</span>}
            <div className="min-w-0 flex-1">
              <div className="truncate font-medium">{suggestion.label}</div>
              {suggestion.description && (
                <div className="text-muted-foreground truncate text-xs">
                  {suggestion.description}
                </div>
              )}
            </div>
          </button>
        ))
      )}
    </div>
  )
}

'use client'

import { cn } from '@/lib/utils'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import type {
  Segment,
  TriggerConfig,
  ActiveTrigger,
  TriggerSuggestion,
  ChipSegment,
  PromptAreaHandle,
} from './types'
import {
  detectActiveTrigger,
  segmentsToPlainText,
  segmentsEqual,
  resolveChip,
  removeChipAtIndex,
  revertChipAtIndex,
  getListContext,
  autoFormatListPrefix,
  insertListContinuation,
  indentListItem,
  outdentListItem,
  removeListPrefix,
  replaceTextRange,
  toggleMarkdownWrap,
} from './prompt-area-engine'
import {
  isHTMLElement,
  isChipElement,
  isLinkElement,
  isBRElement,
  getChipTrigger,
  getChipValue,
  getChipDisplay,
  getChipData,
  getChipAutoResolved,
  getDirectChildContaining,
  indexOfChildNode,
  normalizeEditorDOM,
  decorateURLsInEditor,
  decorateMarkdownInEditor,
  safeJsonStringify,
  getSelectionRange,
} from './dom-helpers'
import { usePromptAreaEvents } from './use-prompt-area-events'
import { useTriggerSearch } from './use-trigger-search'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type UsePromptAreaOptions = {
  value: Segment[]
  onChange: (segments: Segment[]) => void
  triggers?: TriggerConfig[]
  onSubmit?: (segments: Segment[]) => void
  onEscape?: () => void
  onChipClick?: (chip: ChipSegment) => void
  onChipAdd?: (chip: ChipSegment) => void
  onChipDelete?: (chip: ChipSegment) => void
  onLinkClick?: (url: string) => void
  onPaste?: (data: { segments: Segment[]; source: 'internal' | 'external' }) => void
  onUndo?: (segments: Segment[]) => void
  onRedo?: (segments: Segment[]) => void
  onImagePaste?: (file: File) => void
  markdown?: boolean
}

type UsePromptAreaReturn = {
  editorRef: React.RefObject<HTMLDivElement | null>
  activeTrigger: ActiveTrigger | null
  suggestions: TriggerSuggestion[]
  suggestionsLoading: boolean
  suggestionsError: string | null
  selectedSuggestionIndex: number
  handleInput: () => void
  handleKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => void
  handleClick: (e: React.MouseEvent<HTMLDivElement>) => void
  selectSuggestion: (suggestion: TriggerSuggestion) => void
  dismissTrigger: () => void
  handle: PromptAreaHandle
  triggerRect: DOMRect | null
  eventHandlers: {
    onPaste: (e: React.ClipboardEvent<HTMLDivElement>) => void
    onCopy: (e: React.ClipboardEvent<HTMLDivElement>) => void
    onCut: (e: React.ClipboardEvent<HTMLDivElement>) => void
    onDrop: (e: React.DragEvent<HTMLDivElement>) => void
    onDragOver: (e: React.DragEvent<HTMLDivElement>) => void
    onCompositionStart: () => void
    onCompositionEnd: () => void
    onBlur: () => void
  }
}

/** Debounce interval for grouping typed characters into a single undo snapshot */
const UNDO_DEBOUNCE_MS = 300

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function usePromptArea({
  value,
  onChange,
  triggers = [],
  onSubmit,
  onEscape,
  onChipClick,
  onChipAdd,
  onChipDelete,
  onLinkClick,
  onPaste,
  onUndo,
  onRedo,
  onImagePaste,
  markdown: markdownEnabled = true,
}: UsePromptAreaOptions): UsePromptAreaReturn {
  const editorRef = useRef<HTMLDivElement | null>(null)
  const [activeTrigger, setActiveTrigger] = useState<ActiveTrigger | null>(null)
  const [selectedSuggestionIndex, setSelectedSuggestionIndex] = useState(0)
  const [triggerRect, setTriggerRect] = useState<DOMRect | null>(null)

  const {
    suggestions,
    suggestionsLoading,
    suggestionsError,
    search: runSearch,
    reset: resetSearch,
  } = useTriggerSearch()

  // Guard against circular DOM <-> model syncs
  const isSyncing = useRef(false)
  const lastRenderedValue = useRef<Segment[]>([])

  // Debounced undo: groups consecutive keystrokes into a single undo snapshot
  const undoTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  const undoBaseState = useRef<Segment[] | null>(null)

  // -----------------------------------------------------------------------
  // DOM -> Model: read segments from the contentEditable DOM
  // -----------------------------------------------------------------------

  const readSegmentsFromDOM = useCallback((): Segment[] => {
    const editor = editorRef.current
    if (!editor) return []

    const segments: Segment[] = []

    for (let i = 0; i < editor.childNodes.length; i++) {
      const node = editor.childNodes[i]

      if (node.nodeType === Node.TEXT_NODE) {
        const text = node.textContent ?? ''
        if (text) {
          segments.push({ type: 'text', text })
        }
      } else if (isChipElement(node)) {
        // Type-safe chip reading via type guards
        const trigger = getChipTrigger(node)
        const chipValue = getChipValue(node)
        const display = getChipDisplay(node)
        const data = getChipData(node)

        if (trigger && chipValue !== undefined && display) {
          const autoResolved = getChipAutoResolved(node)
          segments.push({
            type: 'chip',
            trigger,
            value: chipValue,
            displayText: display,
            ...(data !== undefined ? { data } : {}),
            ...(autoResolved ? { autoResolved: true } : {}),
          })
        }
      } else if (isBRElement(node)) {
        if (node.dataset.sentinel) continue // skip sentinel <br>
        segments.push({ type: 'text', text: '\n' })
      } else if (isHTMLElement(node)) {
        // Unknown element — extract text content
        const text = node.textContent ?? ''
        if (text) {
          segments.push({ type: 'text', text })
        }
      }
    }

    return segments
  }, [])

  // -----------------------------------------------------------------------
  // Model -> DOM: render segments into the contentEditable div
  // -----------------------------------------------------------------------

  const renderSegmentsToDOM = useCallback(
    (segments: Segment[]) => {
      const editor = editorRef.current
      if (!editor) return

      isSyncing.current = true

      const savedCursor = saveCursorPosition(editor)

      // Clear DOM safely (no innerHTML assignment)
      while (editor.firstChild) {
        editor.removeChild(editor.firstChild)
      }

      for (const seg of segments) {
        if (seg.type === 'text') {
          const lines = seg.text.split('\n')
          for (let lineIdx = 0; lineIdx < lines.length; lineIdx++) {
            if (lines[lineIdx]) {
              editor.appendChild(document.createTextNode(lines[lineIdx]))
            }
            if (lineIdx < lines.length - 1) {
              editor.appendChild(document.createElement('br'))
            }
          }
        } else {
          // Render chip as non-editable span
          const chip = document.createElement('span')
          chip.contentEditable = 'false'
          chip.dataset.chipTrigger = seg.trigger
          chip.dataset.chipValue = seg.value
          chip.dataset.chipDisplay = seg.displayText
          if (seg.data !== undefined) {
            const json = safeJsonStringify(seg.data)
            if (json) {
              chip.dataset.chipData = json
            }
          }
          if (seg.autoResolved) {
            chip.dataset.chipAutoResolved = 'true'
          }
          const triggerConfig = triggers.find((t) => t.char === seg.trigger)
          const chipStyle = triggerConfig?.chipStyle ?? 'pill'
          chip.dataset.chipStyle = chipStyle
          chip.className = cn(
            'prompt-area-chip',
            chipStyle === 'inline' && 'prompt-area-chip--inline',
            triggerConfig?.chipClassName,
          )
          chip.textContent = `${seg.trigger}${seg.displayText}`
          chip.setAttribute('role', 'button')
          chip.setAttribute('tabindex', '-1')
          editor.appendChild(chip)
        }
      }

      // Append sentinel <br> so trailing newlines are visible in contentEditable
      if (editor.lastChild && isBRElement(editor.lastChild)) {
        const sentinel = document.createElement('br')
        sentinel.dataset.sentinel = 'true'
        editor.appendChild(sentinel)
      }

      // Decorate URLs and markdown formatting in text nodes
      decorateURLsInEditor(editor)
      if (markdownEnabled) decorateMarkdownInEditor(editor)

      if (savedCursor) {
        restoreCursorPosition(editor, savedCursor)
      }

      lastRenderedValue.current = segments
      isSyncing.current = false
    },
    [triggers, markdownEnabled],
  )

  // -----------------------------------------------------------------------
  // Trigger detection (extracted so events module can call it)
  // -----------------------------------------------------------------------

  const runTriggerDetection = useCallback(() => {
    const editor = editorRef.current
    if (!editor) return

    const segments = readSegmentsFromDOM()
    const plainText = segmentsToPlainText(segments)
    const cursorPos = getCursorOffset(editor)

    if (cursorPos === null) return

    const detected = detectActiveTrigger(plainText, cursorPos, triggers)

    if (detected) {
      setActiveTrigger(detected)
      setSelectedSuggestionIndex(0)

      // Position the popover at the trigger character, not the cursor.
      // Build a range at detected.startOffset so the dropdown anchors to
      // the trigger char even when the cursor has moved past it.
      const triggerRange = createRangeAtOffset(editor, detected.startOffset)
      if (triggerRange) {
        const rect = triggerRange.getBoundingClientRect()
        // A zero rect means the range couldn't be mapped (e.g. after DOM
        // re-render). Skip updating triggerRect so we keep the last valid one.
        if (rect.height > 0 || rect.left > 0 || rect.top > 0) {
          setTriggerRect(rect)
        }
      }

      // Fetch suggestions for dropdown mode
      if (detected.config.mode === 'dropdown' && detected.config.onSearch) {
        runSearch(detected.query, detected.config)
      }

      // Fire callback for callback mode
      if (detected.config.mode === 'callback' && detected.config.onActivate) {
        detected.config.onActivate({
          text: plainText,
          cursorPosition: cursorPos,
          insertChip: (chip) => {
            const chipResult = resolveChip(segments, detected, {
              value: chip.value,
              displayText: chip.displayText,
              data: chip.data,
            })
            onChange(chipResult.segments)
            renderSegmentsToDOM(chipResult.segments)

            onChipAdd?.({
              type: 'chip',
              trigger: detected.config.char,
              value: chip.value,
              displayText: chip.displayText,
              ...(chip.data !== undefined ? { data: chip.data } : {}),
            })

            const editor = editorRef.current
            if (editor) {
              setCursorAtOffset(editor, chipResult.cursorOffset)
            }
          },
        })
      }
    } else {
      setActiveTrigger(null)
      resetSearch()
    }
  }, [
    triggers,
    readSegmentsFromDOM,
    onChange,
    renderSegmentsToDOM,
    onChipAdd,
    resetSearch,
    runSearch,
  ])

  // -----------------------------------------------------------------------
  // Dismiss trigger
  // -----------------------------------------------------------------------

  const dismissTrigger = useCallback(() => {
    setActiveTrigger(null)
    setSelectedSuggestionIndex(0)
    resetSearch()
  }, [resetSearch])

  // -----------------------------------------------------------------------
  // Wire up edge-case event handlers
  // -----------------------------------------------------------------------

  const events = usePromptAreaEvents({
    editorRef,
    readSegmentsFromDOM,
    onChange,
    renderSegmentsToDOM,
    runTriggerDetection,
    dismissTrigger,
    triggers,
    onPaste,
    onUndo,
    onRedo,
    onChipAdd,
    onImagePaste,
  })

  // -----------------------------------------------------------------------
  // Sync value prop -> DOM on external changes
  // -----------------------------------------------------------------------

  useEffect(() => {
    if (isSyncing.current) return
    if (segmentsEqual(value, lastRenderedValue.current)) return
    renderSegmentsToDOM(value)
  }, [value, renderSegmentsToDOM])

  // Re-render when markdown mode changes to apply/strip decorations
  // Also convert bullet characters: • ↔ - in text segments
  const prevMarkdown = useRef(markdownEnabled)
  useEffect(() => {
    if (prevMarkdown.current === markdownEnabled) return
    prevMarkdown.current = markdownEnabled

    const converted = value.map((seg) => {
      if (seg.type !== 'text') return seg
      // markdown OFF: replace "• " with "- " | markdown ON: replace "- " with "• "
      const newText = markdownEnabled
        ? seg.text.replace(/(^|\n)(\s*)- /g, '$1$2\u2022 ')
        : seg.text.replace(/(^|\n)(\s*)\u2022 /g, '$1$2- ')
      return newText === seg.text ? seg : { ...seg, text: newText }
    })

    const changed = converted.some((seg, i) => seg !== value[i])
    if (changed) {
      onChange(converted)
    } else {
      renderSegmentsToDOM(value)
    }
  }, [markdownEnabled, renderSegmentsToDOM, value, onChange])

  // Clean up undo debounce timer on unmount
  useEffect(() => {
    return () => {
      if (undoTimer.current) clearTimeout(undoTimer.current)
    }
  }, [])

  // -----------------------------------------------------------------------
  // Handle input events
  // -----------------------------------------------------------------------

  const handleInput = useCallback(() => {
    if (isSyncing.current) return

    // During IME composition, sync model but skip trigger detection
    if (events.isComposing.current) {
      const segments = readSegmentsFromDOM()
      lastRenderedValue.current = segments
      onChange(segments)
      return
    }

    const editor = editorRef.current

    // Capture cursor offset BEFORE normalizeEditorDOM strips <a> elements,
    // otherwise the anchor node becomes detached and we lose the position.
    const savedCursorOffset = editor ? getCursorOffset(editor) : null

    if (editor) {
      // Normalize browser-inserted block elements (div, p, font, a, etc.)
      normalizeEditorDOM(editor)
    }

    const segments = readSegmentsFromDOM()

    // Check for list auto-formatting (e.g., "- " -> "bullet ")
    if (markdownEnabled && editor && savedCursorOffset !== null) {
      const formatted = autoFormatListPrefix(segments, savedCursorOffset)
      if (formatted) {
        lastRenderedValue.current = formatted.segments
        onChange(formatted.segments)
        renderSegmentsToDOM(formatted.segments)
        setCursorAtOffset(editor, formatted.cursorOffset)
        runTriggerDetection()
        return
      }
    }

    // Debounced undo: capture the pre-edit state at the start of a typing
    // session and push it to the undo stack after UNDO_DEBOUNCE_MS of idle.
    if (!undoBaseState.current) {
      undoBaseState.current = lastRenderedValue.current
    }

    lastRenderedValue.current = segments
    onChange(segments)
    if (undoTimer.current) clearTimeout(undoTimer.current)
    undoTimer.current = setTimeout(() => {
      if (undoBaseState.current) {
        events.pushUndo(undoBaseState.current)
        undoBaseState.current = null
      }
      undoTimer.current = null
    }, UNDO_DEBOUNCE_MS)

    // Decorate URLs and markdown formatting in text nodes
    if (editor) {
      decorateURLsInEditor(editor)
      if (markdownEnabled) decorateMarkdownInEditor(editor)
      if (savedCursorOffset !== null) {
        setCursorAtOffset(editor, savedCursorOffset)
      }
    }

    runTriggerDetection()
  }, [
    onChange,
    readSegmentsFromDOM,
    runTriggerDetection,
    renderSegmentsToDOM,
    markdownEnabled,
    events,
  ])

  // -----------------------------------------------------------------------
  // Chip click delegation
  // -----------------------------------------------------------------------

  const handleClick = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      const target = e.target
      if (!(target instanceof Node)) return

      const editor = editorRef.current
      if (!editor) return

      // Walk from the click target up to find a link or chip element
      let node: Node | null = target
      while (node && node !== editor) {
        // Check for URL link click — only navigate on Cmd/Ctrl+Click;
        // plain click just positions the cursor for editing.
        if (isLinkElement(node)) {
          if (e.metaKey || e.ctrlKey) {
            e.preventDefault()
            onLinkClick?.(node.href)
            window.open(node.href, '_blank', 'noopener,noreferrer')
            return
          }
          // Plain click: let the browser place the cursor inside the link text
          break
        }

        if (isChipElement(node)) {
          // Spawn ripple effect
          const chipEl = node as HTMLElement
          const rect = chipEl.getBoundingClientRect()
          const ripple = document.createElement('span')
          ripple.className = 'prompt-area-chip-ripple'
          const size = Math.max(rect.width, rect.height)
          ripple.style.width = `${size}px`
          ripple.style.height = `${size}px`
          ripple.style.left = `${e.clientX - rect.left - size / 2}px`
          ripple.style.top = `${e.clientY - rect.top - size / 2}px`
          chipEl.appendChild(ripple)
          ripple.addEventListener('animationend', () => ripple.remove())

          if (!onChipClick) return
          const trigger = getChipTrigger(node)
          const chipValue = getChipValue(node)
          const display = getChipDisplay(node)
          const data = getChipData(node)

          if (trigger && chipValue !== undefined && display) {
            const autoResolved = getChipAutoResolved(node)
            const chip: ChipSegment = {
              type: 'chip',
              trigger,
              value: chipValue,
              displayText: display,
              ...(data !== undefined ? { data } : {}),
              ...(autoResolved ? { autoResolved: true } : {}),
            }
            onChipClick(chip)
          }
          return
        }
        node = node.parentNode
      }
    },
    [onChipClick, onLinkClick],
  )

  // -----------------------------------------------------------------------
  // Remove a chip node from DOM and sync model
  // -----------------------------------------------------------------------

  const removeChipNodeFromDOM = useCallback(
    (editor: HTMLElement, chipNode: HTMLElement): boolean => {
      const segments = readSegmentsFromDOM()
      const chipIdx = indexOfChildNode(editor, chipNode)
      if (chipIdx === -1) return false

      // Map DOM child index to segment index
      let segIdx = 0
      for (let i = 0; i < chipIdx; i++) {
        const child = editor.childNodes[i]
        if (child.nodeType === Node.TEXT_NODE && (child.textContent ?? '') !== '') {
          segIdx++
        } else if (isChipElement(child)) {
          segIdx++
        } else if (isBRElement(child)) {
          segIdx++
        }
      }

      const deletedChip = segments[segIdx]
      const newSegments = removeChipAtIndex(segments, segIdx)
      onChange(newSegments)
      renderSegmentsToDOM(newSegments)

      if (deletedChip?.type === 'chip') {
        onChipDelete?.(deletedChip)
      }

      return true
    },
    [readSegmentsFromDOM, onChange, renderSegmentsToDOM, onChipDelete],
  )

  // -----------------------------------------------------------------------
  // Revert an auto-resolved chip back to plain text
  // -----------------------------------------------------------------------

  const revertChipNodeToText = useCallback(
    (editor: HTMLElement, chipNode: HTMLElement): boolean => {
      const segments = readSegmentsFromDOM()
      const chipIdx = indexOfChildNode(editor, chipNode)
      if (chipIdx === -1) return false

      // Map DOM child index to segment index
      let segIdx = 0
      for (let i = 0; i < chipIdx; i++) {
        const child = editor.childNodes[i]
        if (child.nodeType === Node.TEXT_NODE && (child.textContent ?? '') !== '') {
          segIdx++
        } else if (isChipElement(child)) {
          segIdx++
        } else if (isBRElement(child)) {
          segIdx++
        }
      }

      const revertedChip = segments[segIdx]
      const result = revertChipAtIndex(segments, segIdx)
      if (!result) return false

      // Compute cursor target: plain text offset at end of reverted text
      let targetOffset = 0
      for (let i = 0; i < segIdx; i++) {
        const s = segments[i]
        if (s.type === 'text') {
          targetOffset += s.text.length
        } else {
          targetOffset += s.trigger.length + s.displayText.length
        }
      }
      targetOffset += result.revertedText.length

      onChange(result.segments)
      renderSegmentsToDOM(result.segments)
      setCursorAtOffset(editor, targetOffset)

      if (revertedChip?.type === 'chip') {
        onChipDelete?.(revertedChip)
      }

      return true
    },
    [readSegmentsFromDOM, onChange, renderSegmentsToDOM, onChipDelete],
  )

  // -----------------------------------------------------------------------
  // Chip backspace (delete chip behind cursor as whole unit)
  // -----------------------------------------------------------------------

  const handleChipBackspace = useCallback((): boolean => {
    const editor = editorRef.current
    if (!editor) return false

    const range = getSelectionRange()
    if (!range || !range.collapsed) return false

    const node = range.startContainer
    const offset = range.startOffset

    // Case 1: cursor is at the editor level (between child nodes)
    if (node === editor && offset > 0) {
      const prevChild = editor.childNodes[offset - 1]
      if (prevChild && isChipElement(prevChild)) {
        if (getChipAutoResolved(prevChild)) {
          return revertChipNodeToText(editor, prevChild)
        }
        return removeChipNodeFromDOM(editor, prevChild)
      }
    }

    // Case 2: cursor is at start of a text node, check previous sibling
    if (node.nodeType === Node.TEXT_NODE && offset === 0) {
      const directChild = getDirectChildContaining(editor, node)
      if (!directChild) return false

      let prevSibling = directChild.previousSibling
      while (
        prevSibling &&
        prevSibling.nodeType === Node.TEXT_NODE &&
        prevSibling.textContent === ''
      ) {
        prevSibling = prevSibling.previousSibling
      }
      if (prevSibling && isChipElement(prevSibling)) {
        if (getChipAutoResolved(prevSibling)) {
          return revertChipNodeToText(editor, prevSibling)
        }
        return removeChipNodeFromDOM(editor, prevSibling)
      }
    }

    return false
  }, [removeChipNodeFromDOM, revertChipNodeToText])

  // -----------------------------------------------------------------------
  // Chip forward delete (delete chip in front of cursor)
  // -----------------------------------------------------------------------

  const handleChipForwardDelete = useCallback((): boolean => {
    const editor = editorRef.current
    if (!editor) return false

    const range = getSelectionRange()
    if (!range || !range.collapsed) return false

    const node = range.startContainer
    const offset = range.startOffset

    // Case 1: cursor at the editor level
    if (node === editor && offset < editor.childNodes.length) {
      const nextChild = editor.childNodes[offset]
      if (nextChild && isChipElement(nextChild)) {
        return removeChipNodeFromDOM(editor, nextChild)
      }
    }

    // Case 2: cursor at end of a text node, check next sibling
    if (node.nodeType === Node.TEXT_NODE && offset === (node.textContent ?? '').length) {
      const directChild = getDirectChildContaining(editor, node)
      if (!directChild) return false

      let nextSibling = directChild.nextSibling
      while (
        nextSibling &&
        nextSibling.nodeType === Node.TEXT_NODE &&
        nextSibling.textContent === ''
      ) {
        nextSibling = nextSibling.nextSibling
      }
      if (nextSibling && isChipElement(nextSibling)) {
        return removeChipNodeFromDOM(editor, nextSibling)
      }
    }

    return false
  }, [removeChipNodeFromDOM])

  // -----------------------------------------------------------------------
  // Auto-resolve active trigger on space
  // -----------------------------------------------------------------------

  const autoResolveActiveTrigger = useCallback(
    (trigger: ActiveTrigger) => {
      const segments = readSegmentsFromDOM()
      const query = trigger.query

      // Create a synthetic suggestion so onSelect can customize display text
      const syntheticSuggestion: TriggerSuggestion = {
        value: query,
        label: query,
      }

      const displayText = trigger.config.onSelect?.(syntheticSuggestion) ?? query

      const chipData = {
        value: query,
        displayText: displayText || query,
        autoResolved: true,
      }
      const result = resolveChip(segments, trigger, chipData)

      onChange(result.segments)
      renderSegmentsToDOM(result.segments)

      onChipAdd?.({
        type: 'chip',
        trigger: trigger.config.char,
        ...chipData,
      })

      // Position cursor after the auto-resolved chip + trailing space
      const editor = editorRef.current
      if (editor) {
        setCursorAtOffset(editor, result.cursorOffset)
      }

      dismissTrigger()
    },
    [readSegmentsFromDOM, onChange, renderSegmentsToDOM, dismissTrigger, onChipAdd],
  )

  // -----------------------------------------------------------------------
  // Select a suggestion from the dropdown
  // -----------------------------------------------------------------------

  const selectSuggestionInternal = useCallback(
    (suggestion: TriggerSuggestion) => {
      if (!activeTrigger) return

      const segments = readSegmentsFromDOM()
      const displayText = activeTrigger.config.onSelect?.(suggestion) ?? suggestion.label

      const chipData = {
        value: suggestion.value,
        displayText: displayText || suggestion.label,
        data: suggestion.data,
      }
      const result = resolveChip(segments, activeTrigger, chipData)

      onChange(result.segments)
      renderSegmentsToDOM(result.segments)

      onChipAdd?.({
        type: 'chip',
        trigger: activeTrigger.config.char,
        ...chipData,
      })

      // Position cursor after the chip + trailing space
      const editor = editorRef.current
      if (editor) {
        setCursorAtOffset(editor, result.cursorOffset)
      }

      dismissTrigger()

      // Refocus editor after popover interaction
      setTimeout(() => {
        editorRef.current?.focus()
      }, 0)
    },
    [activeTrigger, readSegmentsFromDOM, onChange, renderSegmentsToDOM, dismissTrigger, onChipAdd],
  )

  const selectSuggestion = selectSuggestionInternal

  // -----------------------------------------------------------------------
  // Handle key events
  // -----------------------------------------------------------------------

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      const applyEditResult = (
        editor: HTMLDivElement,
        result: { segments: Segment[]; cursorOffset: number },
      ) => {
        lastRenderedValue.current = result.segments
        onChange(result.segments)
        renderSegmentsToDOM(result.segments)
        setCursorAtOffset(editor, result.cursorOffset)
      }

      const tryListContinuation = (editor: HTMLDivElement): boolean => {
        if (!markdownEnabled) return false
        const segments = readSegmentsFromDOM()
        const cursorPos = getCursorOffset(editor)
        if (cursorPos === null) return false
        const plainText = segmentsToPlainText(segments)
        if (!getListContext(plainText, cursorPos)) return false
        const result = insertListContinuation(segments, cursorPos)
        if (result) applyEditResult(editor, result)
        return true
      }

      // 1. Flush pending undo debounce so Cmd+Z has the latest checkpoint
      if ((e.metaKey || e.ctrlKey) && e.key === 'z' && undoBaseState.current) {
        if (undoTimer.current) {
          clearTimeout(undoTimer.current)
          undoTimer.current = null
        }
        events.pushUndo(undoBaseState.current)
        undoBaseState.current = null
      }

      // 1a. Undo/redo intercept
      if (events.handleKeyDownForUndoRedo(e)) return

      // 1.5 Markdown formatting shortcuts (Cmd+B bold, Cmd+I italic)
      if (
        markdownEnabled &&
        (e.metaKey || e.ctrlKey) &&
        !e.shiftKey &&
        (e.key === 'b' || e.key === 'i')
      ) {
        e.preventDefault()
        const editor = editorRef.current
        if (!editor) return

        const offsets = getSelectionOffsets(editor)
        if (!offsets || offsets.start === offsets.end) return

        const marker = e.key === 'b' ? '**' : '*'
        const currentSegments = readSegmentsFromDOM()
        events.pushUndo(currentSegments)

        const result = toggleMarkdownWrap(currentSegments, offsets.start, offsets.end, marker)
        if (!result) return

        lastRenderedValue.current = result.segments
        onChange(result.segments)
        renderSegmentsToDOM(result.segments)
        setSelectionAtOffsets(editor, result.selectionStart, result.selectionEnd)
        return
      }

      // 2. Trigger dropdown navigation
      if (activeTrigger && activeTrigger.config.mode === 'dropdown' && suggestions.length > 0) {
        if (e.key === 'ArrowDown') {
          e.preventDefault()
          setSelectedSuggestionIndex((prev) => Math.min(prev + 1, suggestions.length - 1))
          return
        }
        if (e.key === 'ArrowUp') {
          e.preventDefault()
          setSelectedSuggestionIndex((prev) => Math.max(prev - 1, 0))
          return
        }
        if (e.key === 'Enter' || e.key === 'Tab') {
          e.preventDefault()
          const selected = suggestions[selectedSuggestionIndex]
          if (selected) {
            selectSuggestionInternal(selected)
          }
          return
        }
        if (e.key === 'Escape') {
          e.preventDefault()
          dismissTrigger()
          return
        }
      }

      // 2.5. Auto-resolve on Space when trigger has resolveOnSpace
      if (e.key === ' ' && activeTrigger && activeTrigger.config.resolveOnSpace) {
        const query = activeTrigger.query.trim()
        if (query.length > 0) {
          e.preventDefault()
          autoResolveActiveTrigger(activeTrigger)
          return
        }
      }

      // 2.6. Tab/Shift+Tab for list indentation (only when trigger dropdown is NOT open)
      if (markdownEnabled && e.key === 'Tab' && !activeTrigger) {
        const editor = editorRef.current
        if (editor) {
          const segments = readSegmentsFromDOM()
          const plainText = segmentsToPlainText(segments)
          const cursorPos = getCursorOffset(editor)
          if (cursorPos !== null) {
            const ctx = getListContext(plainText, cursorPos)
            if (ctx) {
              e.preventDefault()
              const result = e.shiftKey
                ? outdentListItem(segments, cursorPos)
                : indentListItem(segments, cursorPos)
              if (result) applyEditResult(editor, result)
              return
            }
          }
        }
      }

      // 2.8 Shift+Enter: insert newline at model level (avoids browser's broken
      // contentEditable behavior near <a> elements)
      if (e.key === 'Enter' && e.shiftKey && !e.nativeEvent.isComposing) {
        e.preventDefault()
        const editor = editorRef.current
        if (editor) {
          // Check for list continuation first (same as Enter)
          if (tryListContinuation(editor)) return
          // Fallback: plain newline (existing behavior)
          const offsets = getSelectionOffsets(editor)
          if (offsets) {
            const currentSegments = readSegmentsFromDOM()
            events.pushUndo(currentSegments)
            const newSegments = replaceTextRange(currentSegments, offsets.start, offsets.end, '\n')
            applyEditResult(editor, { segments: newSegments, cursorOffset: offsets.start + 1 })
          }
        }
        return
      }

      // 3. Submit on Enter (without Shift), skip during IME
      if (e.key === 'Enter' && !e.shiftKey && !e.nativeEvent.isComposing) {
        // 3a. Check for list continuation first (only when markdown is enabled)
        const editor = editorRef.current
        if (editor && tryListContinuation(editor)) {
          e.preventDefault()
          return
        }

        // 3b. Submit (if no list context)
        if (onSubmit) {
          e.preventDefault()
          onSubmit(readSegmentsFromDOM())
          return
        }
      }

      // 4. Escape
      if (e.key === 'Escape' && onEscape) {
        onEscape()
        return
      }

      // 4.5 Non-collapsed selection delete (Backspace/Delete across <a> boundaries)
      if ((e.key === 'Backspace' || e.key === 'Delete') && !e.nativeEvent.isComposing) {
        const editor = editorRef.current
        if (editor) {
          const offsets = getSelectionOffsets(editor)
          if (offsets && offsets.start !== offsets.end) {
            e.preventDefault()
            const currentSegments = readSegmentsFromDOM()
            events.pushUndo(currentSegments)
            const newSegments = replaceTextRange(currentSegments, offsets.start, offsets.end, '')
            applyEditResult(editor, { segments: newSegments, cursorOffset: offsets.start })
            runTriggerDetection()
            return
          }
        }
      }

      // 5. Backspace: check list prefix removal, then chip deletion
      if (e.key === 'Backspace') {
        const editor = editorRef.current
        if (editor) {
          const segments = readSegmentsFromDOM()
          const cursorPos = getCursorOffset(editor)
          if (markdownEnabled && cursorPos !== null) {
            const result = removeListPrefix(segments, cursorPos)
            if (result) {
              e.preventDefault()
              applyEditResult(editor, result)
              runTriggerDetection()
              return
            }
          }
        }
        if (handleChipBackspace()) {
          e.preventDefault()
          runTriggerDetection()
          return
        }
      }

      // 6. Delete (forward): delete chip as whole unit
      if (e.key === 'Delete' && handleChipForwardDelete()) {
        e.preventDefault()
        runTriggerDetection()
        return
      }
    },
    [
      activeTrigger,
      suggestions,
      selectedSuggestionIndex,
      onSubmit,
      onEscape,
      readSegmentsFromDOM,
      onChange,
      renderSegmentsToDOM,
      markdownEnabled,
      dismissTrigger,
      handleChipBackspace,
      handleChipForwardDelete,
      autoResolveActiveTrigger,
      runTriggerDetection,
      selectSuggestionInternal,
      events,
    ],
  )

  // -----------------------------------------------------------------------
  // Imperative handle (memoized to avoid identity changes)
  // -----------------------------------------------------------------------

  const handle: PromptAreaHandle = useMemo(
    () => ({
      focus: () => editorRef.current?.focus(),
      blur: () => editorRef.current?.blur(),
      insertChip: (chip) => {
        const segments = readSegmentsFromDOM()
        const newChip: ChipSegment = { type: 'chip', ...chip }
        const newSegments: Segment[] = [...segments, newChip, { type: 'text', text: ' ' }]
        onChange(newSegments)
        renderSegmentsToDOM(newSegments)
        onChipAdd?.(newChip)
      },
      getPlainText: () => segmentsToPlainText(readSegmentsFromDOM()),
      clear: () => {
        onChange([])
        const editor = editorRef.current
        if (editor) {
          while (editor.firstChild) editor.removeChild(editor.firstChild)
        }
        events.resetUndoHistory()
        if (undoTimer.current) {
          clearTimeout(undoTimer.current)
          undoTimer.current = null
        }
        undoBaseState.current = null
      },
    }),
    [readSegmentsFromDOM, onChange, renderSegmentsToDOM, onChipAdd, events],
  )

  // -----------------------------------------------------------------------
  // Compose event handlers
  // -----------------------------------------------------------------------

  const eventHandlers = useMemo(
    () => ({
      onPaste: events.handlePaste,
      onCopy: events.handleCopy,
      onCut: events.handleCut,
      onDrop: events.handleDrop,
      onDragOver: events.handleDragOver,
      onCompositionStart: events.handleCompositionStart,
      onCompositionEnd: events.handleCompositionEnd,
      onBlur: events.handleBlur,
    }),
    [
      events.handlePaste,
      events.handleCopy,
      events.handleCut,
      events.handleDrop,
      events.handleDragOver,
      events.handleCompositionStart,
      events.handleCompositionEnd,
      events.handleBlur,
    ],
  )

  return {
    editorRef,
    activeTrigger,
    suggestions,
    suggestionsLoading,
    suggestionsError,
    selectedSuggestionIndex,
    handleInput,
    handleKeyDown,
    handleClick,
    selectSuggestion,
    dismissTrigger,
    handle,
    triggerRect,
    eventHandlers,
  }
}

// ---------------------------------------------------------------------------
// Cursor position utilities (private to this module)
// ---------------------------------------------------------------------------

type SavedCursor = {
  nodeIndex: number
  offset: number
}

function saveCursorPosition(editor: HTMLElement): SavedCursor | null {
  const range = getSelectionRange()
  if (!range) return null
  if (!editor.contains(range.startContainer)) return null

  const node = range.startContainer
  if (node === editor) {
    return { nodeIndex: range.startOffset, offset: 0 }
  }

  // Walk up to find the direct child of editor using type-safe helper
  const directChild = getDirectChildContaining(editor, node)
  if (!directChild) return null

  const nodeIndex = indexOfChildNode(editor, directChild)
  return { nodeIndex, offset: range.startOffset }
}

function restoreCursorPosition(editor: HTMLElement, saved: SavedCursor): void {
  const sel = window.getSelection()
  if (!sel) return

  const childNodes = editor.childNodes
  if (childNodes.length === 0) return

  const range = document.createRange()

  if (saved.nodeIndex >= childNodes.length) {
    const lastChild = childNodes[childNodes.length - 1]
    if (lastChild.nodeType === Node.TEXT_NODE) {
      range.setStart(lastChild, (lastChild.textContent ?? '').length)
    } else {
      range.setStartAfter(lastChild)
    }
  } else {
    const targetNode = childNodes[saved.nodeIndex]
    if (targetNode.nodeType === Node.TEXT_NODE) {
      const maxOffset = (targetNode.textContent ?? '').length
      range.setStart(targetNode, Math.min(saved.offset, maxOffset))
    } else {
      range.setStartAfter(targetNode)
    }
  }

  range.collapse(true)
  sel.removeAllRanges()
  sel.addRange(range)
}

function getCursorOffset(editor: HTMLElement): number | null {
  const range = getSelectionRange()
  if (!range) return null
  if (!editor.contains(range.startContainer)) return null

  const preRange = document.createRange()
  preRange.selectNodeContents(editor)
  preRange.setEnd(range.startContainer, range.startOffset)

  return getTextLengthInRange(preRange)
}

/**
 * Create a collapsed Range at the given plain-text offset inside the editor.
 * Returns null if the offset can't be mapped to a DOM position.
 */
function createRangeAtOffset(editor: HTMLElement, targetOffset: number): Range | null {
  const pos = findDOMPosition(editor, targetOffset)
  if (!pos) return null

  const range = document.createRange()
  range.setStart(pos.node, pos.offset)
  range.collapse(true)
  return range
}

function setCursorAtOffset(editor: HTMLElement, targetOffset: number): void {
  const sel = window.getSelection()
  if (!sel) return

  const pos = findDOMPosition(editor, targetOffset)
  if (pos) {
    const range = document.createRange()
    range.setStart(pos.node, pos.offset)
    range.collapse(true)
    sel.removeAllRanges()
    sel.addRange(range)
    return
  }

  // Fallback: place cursor at end
  const range = document.createRange()
  range.selectNodeContents(editor)
  range.collapse(false)
  sel.removeAllRanges()
  sel.addRange(range)
}

function getTextLengthInRange(range: Range): number {
  const fragment = range.cloneContents()
  let length = 0

  const walk = (node: Node): void => {
    if (node.nodeType === Node.TEXT_NODE) {
      length += (node.textContent ?? '').length
    } else if (isChipElement(node)) {
      // Type-safe chip reading
      const trigger = node.dataset.chipTrigger ?? ''
      const display = node.dataset.chipDisplay ?? node.textContent ?? ''
      length += trigger.length + display.length
    } else if (isHTMLElement(node) && node.tagName === 'BR') {
      if (node.dataset.sentinel) return // skip sentinel <br>
      length += 1
    } else if (isHTMLElement(node)) {
      node.childNodes.forEach(walk)
    }
  }

  fragment.childNodes.forEach(walk)
  return length
}

/**
 * Returns the start and end plain-text offsets of the current selection.
 * Returns null if there's no selection or it's outside the editor.
 */
function getSelectionOffsets(editor: HTMLElement): { start: number; end: number } | null {
  const range = getSelectionRange()
  if (!range) return null
  if (!editor.contains(range.startContainer)) return null

  const startRange = document.createRange()
  startRange.selectNodeContents(editor)
  startRange.setEnd(range.startContainer, range.startOffset)
  const start = getTextLengthInRange(startRange)

  if (range.collapsed) return { start, end: start }

  const endRange = document.createRange()
  endRange.selectNodeContents(editor)
  endRange.setEnd(range.endContainer, range.endOffset)
  const end = getTextLengthInRange(endRange)

  return { start, end }
}

/**
 * Sets a (potentially non-collapsed) selection at the given plain-text offsets.
 * Used to restore selection after markdown wrap/unwrap operations.
 */
function setSelectionAtOffsets(editor: HTMLElement, startOffset: number, endOffset: number): void {
  const sel = window.getSelection()
  if (!sel) return

  if (startOffset === endOffset) {
    setCursorAtOffset(editor, startOffset)
    return
  }

  const startPos = findDOMPosition(editor, startOffset)
  const endPos = findDOMPosition(editor, endOffset)
  if (!startPos || !endPos) return

  const range = document.createRange()
  range.setStart(startPos.node, startPos.offset)
  range.setEnd(endPos.node, endPos.offset)
  sel.removeAllRanges()
  sel.addRange(range)
}

/**
 * Maps a plain-text offset to a DOM node + offset pair.
 * Recurses into decoration elements (markdown spans, URL anchors).
 */
function findDOMPosition(
  container: HTMLElement,
  targetOffset: number,
): { node: Node; offset: number } | null {
  let remaining = targetOffset

  for (let i = 0; i < container.childNodes.length; i++) {
    const child = container.childNodes[i]

    if (child.nodeType === Node.TEXT_NODE) {
      const len = (child.textContent ?? '').length
      if (remaining <= len) {
        return { node: child, offset: remaining }
      }
      remaining -= len
    } else if (isChipElement(child)) {
      const trigger = child.dataset.chipTrigger ?? ''
      const display = child.dataset.chipDisplay ?? child.textContent ?? ''
      const chipLen = trigger.length + display.length
      if (remaining <= chipLen) {
        // Position after the chip element
        return { node: container, offset: i + 1 }
      }
      remaining -= chipLen
    } else if (isBRElement(child)) {
      if (child.dataset.sentinel) continue // skip sentinel <br>
      if (remaining <= 1) {
        return { node: container, offset: i + 1 }
      }
      remaining -= 1
    } else if (isHTMLElement(child)) {
      // Decoration element (markdown span, URL anchor) — recurse
      const textLen = (child.textContent ?? '').length
      if (remaining <= textLen) {
        const result = findDOMPosition(child, remaining)
        if (result) return result
      }
      remaining -= textLen
    }
  }

  // Fallback: end of container
  return { node: container, offset: container.childNodes.length }
}

'use client'

import { useCallback, useRef } from 'react'
import type { Segment, ChipSegment, TriggerConfig } from './types'
import { resolveTriggersInSegments } from './prompt-area-engine'
import {
  isChipElement,
  isHTMLElement,
  normalizeEditorDOM,
  getChipTrigger,
  getChipValue,
  getChipDisplay,
  getChipData,
  getChipAutoResolved,
  safeJsonStringify,
  getSelectionRange,
} from './dom-helpers'

// ---------------------------------------------------------------------------
// Type Guards
// ---------------------------------------------------------------------------

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value)
}

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type EventHandlerDeps = {
  editorRef: React.RefObject<HTMLDivElement | null>
  readSegmentsFromDOM: () => Segment[]
  onChange: (segments: Segment[]) => void
  renderSegmentsToDOM: (segments: Segment[]) => void
  runTriggerDetection: () => void
  dismissTrigger: () => void
  triggers: TriggerConfig[]
  onPaste?: (data: { segments: Segment[]; source: 'internal' | 'external' }) => void
  onUndo?: (segments: Segment[]) => void
  onRedo?: (segments: Segment[]) => void
  onChipAdd?: (chip: ChipSegment) => void
  onImagePaste?: (file: File) => void
}

type PromptAreaEventHandlers = {
  handlePaste: (e: React.ClipboardEvent<HTMLDivElement>) => void
  handleCopy: (e: React.ClipboardEvent<HTMLDivElement>) => void
  handleCut: (e: React.ClipboardEvent<HTMLDivElement>) => void
  handleDrop: (e: React.DragEvent<HTMLDivElement>) => void
  handleDragOver: (e: React.DragEvent<HTMLDivElement>) => void
  handleCompositionStart: () => void
  handleCompositionEnd: () => void
  handleBlur: () => void
  handleKeyDownForUndoRedo: (e: React.KeyboardEvent<HTMLDivElement>) => boolean
  pushUndo: (segments: Segment[]) => void
  resetUndoHistory: () => void
  isComposing: React.RefObject<boolean>
}

// ---------------------------------------------------------------------------
// Undo/Redo Stack
// ---------------------------------------------------------------------------

const MAX_UNDO_HISTORY = 100

/** Delay before dismissing trigger on blur, so popover clicks register first */
export const BLUR_DELAY_MS = 150

type UndoState = {
  undoStack: Segment[][]
  redoStack: Segment[][]
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Encapsulates all edge-case event handlers for the prompt area component:
 * paste, copy, cut, drag/drop, IME composition, blur, and undo/redo.
 */
export function usePromptAreaEvents(deps: EventHandlerDeps): PromptAreaEventHandlers {
  const {
    editorRef,
    readSegmentsFromDOM,
    onChange,
    renderSegmentsToDOM,
    runTriggerDetection,
    dismissTrigger,
    triggers,
    onPaste: onPasteCallback,
    onUndo,
    onRedo,
    onChipAdd,
    onImagePaste,
  } = deps

  const isComposing = useRef(false)
  const undoState = useRef<UndoState>({ undoStack: [], redoStack: [] })

  // Track previous segments for undo stack
  const prevSegments = useRef<Segment[]>([])

  /**
   * Push current state onto the undo stack.
   * Called before any programmatic change.
   */
  const pushUndo = useCallback((segments: Segment[]) => {
    const state = undoState.current
    state.undoStack.push(segments)
    if (state.undoStack.length > MAX_UNDO_HISTORY) {
      state.undoStack.shift()
    }
    // Clear redo stack on new change
    state.redoStack = []
  }, [])

  const resetUndoHistory = useCallback(() => {
    undoState.current = { undoStack: [], redoStack: [] }
    prevSegments.current = []
  }, [])

  // -----------------------------------------------------------------------
  // Paste: strip HTML, insert plain text only
  // -----------------------------------------------------------------------

  const handlePaste = useCallback(
    (e: React.ClipboardEvent<HTMLDivElement>) => {
      e.preventDefault()

      const editor = editorRef.current
      if (!editor) return

      // Check for image files in clipboard before processing text
      // Some browsers/OSes provide pasted images via `items` instead of `files` (e.g. screenshots)
      const imageFile =
        Array.from(e.clipboardData.files).find((f) => f.type.startsWith('image/')) ??
        (() => {
          const item = Array.from(e.clipboardData.items).find((i) => i.type.startsWith('image/'))
          return item?.getAsFile() ?? null
        })()
      if (imageFile) {
        onImagePaste?.(imageFile)
        return
      }

      // Record undo snapshot
      const currentSegments = readSegmentsFromDOM()
      pushUndo(currentSegments)

      // Check for internal segment data (copy/paste within the editor)
      const segmentJson = e.clipboardData.getData('text/prompt-area-segments')
      if (segmentJson) {
        const parsed = parseSegmentsFromClipboard(segmentJson)
        if (parsed && parsed.length > 0) {
          // Insert the copied segments at cursor position
          const range = getSelectionRange()
          if (!range) return

          range.deleteContents()

          // Merge pasted segments into current segments at cursor position
          const beforePaste = readSegmentsFromDOM()
          const merged = insertSegmentsAtCursor(beforePaste, parsed, editor)
          prevSegments.current = merged
          onChange(merged)
          renderSegmentsToDOM(merged)

          // Notify: internal paste with chip data preserved
          onPasteCallback?.({ segments: merged, source: 'internal' })
          for (const seg of parsed) {
            if (seg.type === 'chip') {
              onChipAdd?.(seg)
            }
          }

          runTriggerDetection()
          return
        }
      }

      // Fall back to plain text paste
      const text = e.clipboardData.getData('text/plain')
      if (!text) return

      // Insert plain text at cursor position using Selection API
      const range = getSelectionRange()
      if (!range) return

      range.deleteContents()

      // Handle multi-line paste: split into lines with BR elements
      const lines = text.split('\n')
      const fragment = document.createDocumentFragment()

      for (let i = 0; i < lines.length; i++) {
        if (lines[i]) {
          fragment.appendChild(document.createTextNode(lines[i]))
        }
        if (i < lines.length - 1) {
          fragment.appendChild(document.createElement('br'))
        }
      }

      range.insertNode(fragment)

      // Move cursor to end of pasted content
      range.collapse(false)
      const sel = window.getSelection()
      sel?.removeAllRanges()
      sel?.addRange(range)

      // Normalize DOM, sync model, detect triggers
      normalizeEditorDOM(editor)
      const newSegments = readSegmentsFromDOM()

      // Auto-resolve trigger patterns in pasted text (e.g., #readme -> chip)
      const resolvedSegments = resolveTriggersInSegments(newSegments, triggers)

      if (resolvedSegments !== newSegments) {
        prevSegments.current = resolvedSegments
        onChange(resolvedSegments)
        renderSegmentsToDOM(resolvedSegments)

        // Notify about auto-resolved chips from pasted text
        for (const seg of resolvedSegments) {
          if (
            seg.type === 'chip' &&
            !newSegments.some(
              (s) =>
                s.type === 'chip' &&
                s.trigger === seg.trigger &&
                s.value === seg.value &&
                s.displayText === seg.displayText,
            )
          ) {
            onChipAdd?.(seg)
          }
        }
      } else {
        prevSegments.current = newSegments
        onChange(newSegments)
      }

      onPasteCallback?.({ segments: resolvedSegments, source: 'external' })
      runTriggerDetection()
    },
    [
      editorRef,
      readSegmentsFromDOM,
      onChange,
      pushUndo,
      runTriggerDetection,
      renderSegmentsToDOM,
      triggers,
      onPasteCallback,
      onChipAdd,
      onImagePaste,
    ],
  )

  // -----------------------------------------------------------------------
  // Copy: serialize chips into plain text
  // -----------------------------------------------------------------------

  const handleCopy = useCallback((e: React.ClipboardEvent<HTMLDivElement>) => {
    e.preventDefault()

    const range = getSelectionRange()
    if (!range) return

    const fragment = range.cloneContents()

    // Walk fragment and serialize, converting chips to their text representation
    const plainText = serializeFragmentToPlainText(fragment)
    e.clipboardData.setData('text/plain', plainText)

    // Also serialize chip segments as JSON for internal paste
    const fragmentSegments = serializeFragmentToSegments(fragment)
    const hasChips = fragmentSegments.some((s) => s.type === 'chip')
    if (hasChips) {
      const json = safeJsonStringify(fragmentSegments)
      if (json) {
        e.clipboardData.setData('text/prompt-area-segments', json)
      }
    }
  }, [])

  // -----------------------------------------------------------------------
  // Cut: copy + delete
  // -----------------------------------------------------------------------

  const handleCut = useCallback(
    (e: React.ClipboardEvent<HTMLDivElement>) => {
      // First, do the copy
      handleCopy(e)

      // Then delete the selection
      const range = getSelectionRange()
      if (!range) return

      const currentSegments = readSegmentsFromDOM()
      pushUndo(currentSegments)

      range.deleteContents()

      const editor = editorRef.current
      if (editor) {
        normalizeEditorDOM(editor)
      }

      const newSegments = readSegmentsFromDOM()
      prevSegments.current = newSegments
      onChange(newSegments)
      runTriggerDetection()
    },
    [handleCopy, editorRef, readSegmentsFromDOM, onChange, pushUndo, runTriggerDetection],
  )

  // -----------------------------------------------------------------------
  // Drag & Drop: prevent to avoid unpredictable DOM mutations
  // -----------------------------------------------------------------------

  const handleDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault()
  }, [])

  const handleDragOver = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault()
  }, [])

  // -----------------------------------------------------------------------
  // IME Composition: track state, defer trigger detection
  // -----------------------------------------------------------------------

  const handleCompositionStart = useCallback(() => {
    isComposing.current = true
  }, [])

  const handleCompositionEnd = useCallback(() => {
    isComposing.current = false
    // Run trigger detection after composition ends
    runTriggerDetection()
  }, [runTriggerDetection])

  // -----------------------------------------------------------------------
  // Blur: dismiss trigger dropdown with delay (so popover clicks work)
  // -----------------------------------------------------------------------

  const handleBlur = useCallback(() => {
    setTimeout(() => {
      const editor = editorRef.current
      if (!editor) return

      // Only dismiss if focus didn't move to an element within the editor container
      const activeEl = document.activeElement
      if (activeEl && editor.parentElement?.contains(activeEl)) return

      dismissTrigger()
    }, BLUR_DELAY_MS)
  }, [editorRef, dismissTrigger])

  // -----------------------------------------------------------------------
  // Undo/Redo: intercept Ctrl+Z / Ctrl+Shift+Z
  // -----------------------------------------------------------------------

  const handleKeyDownForUndoRedo = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>): boolean => {
      const isMeta = e.metaKey || e.ctrlKey

      if (!isMeta || e.key !== 'z') return false

      e.preventDefault()
      const state = undoState.current

      if (e.shiftKey) {
        // Redo: Ctrl+Shift+Z
        if (state.redoStack.length === 0) return true

        const segments = state.redoStack.pop()
        if (!segments) return true

        const current = readSegmentsFromDOM()
        state.undoStack.push(current)

        prevSegments.current = segments
        onChange(segments)
        renderSegmentsToDOM(segments)
        onRedo?.(segments)
      } else {
        // Undo: Ctrl+Z
        if (state.undoStack.length === 0) return true

        const segments = state.undoStack.pop()
        if (!segments) return true

        const current = readSegmentsFromDOM()
        state.redoStack.push(current)

        prevSegments.current = segments
        onChange(segments)
        renderSegmentsToDOM(segments)
        onUndo?.(segments)
      }

      return true
    },
    [readSegmentsFromDOM, onChange, renderSegmentsToDOM, onUndo, onRedo],
  )

  return {
    handlePaste,
    handleCopy,
    handleCut,
    handleDrop,
    handleDragOver,
    handleCompositionStart,
    handleCompositionEnd,
    handleBlur,
    handleKeyDownForUndoRedo,
    pushUndo,
    resetUndoHistory,
    isComposing,
  }
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Serializes a DocumentFragment (from selection) to plain text,
 * converting chip elements to their `trigger + displayText` form.
 */
function serializeFragmentToPlainText(fragment: DocumentFragment): string {
  let text = ''

  const walk = (node: Node): void => {
    if (node.nodeType === Node.TEXT_NODE) {
      text += node.textContent ?? ''
    } else if (isChipElement(node)) {
      const trigger = node.dataset.chipTrigger ?? ''
      const display = node.dataset.chipDisplay ?? node.textContent ?? ''
      text += trigger + display
    } else if (isHTMLElement(node) && node.tagName === 'BR') {
      text += '\n'
    } else {
      node.childNodes.forEach(walk)
    }
  }

  fragment.childNodes.forEach(walk)
  return text
}

/**
 * Serializes a DocumentFragment to an array of Segment objects,
 * preserving chip data for internal copy/paste.
 */
function serializeFragmentToSegments(fragment: DocumentFragment): Segment[] {
  const segments: Segment[] = []

  const walk = (node: Node): void => {
    if (node.nodeType === Node.TEXT_NODE) {
      const text = node.textContent ?? ''
      if (text) {
        segments.push({ type: 'text', text })
      }
    } else if (isChipElement(node)) {
      const trigger = getChipTrigger(node)
      const chipValue = getChipValue(node)
      const display = getChipDisplay(node)
      const data = getChipData(node)
      const autoResolved = getChipAutoResolved(node)

      if (trigger && chipValue !== undefined && display) {
        const chip: ChipSegment = {
          type: 'chip',
          trigger,
          value: chipValue,
          displayText: display,
          ...(data !== undefined ? { data } : {}),
          ...(autoResolved ? { autoResolved: true } : {}),
        }
        segments.push(chip)
      }
    } else if (isHTMLElement(node) && node.tagName === 'BR') {
      segments.push({ type: 'text', text: '\n' })
    } else {
      node.childNodes.forEach(walk)
    }
  }

  fragment.childNodes.forEach(walk)
  return segments
}

/**
 * Parses segment JSON from the clipboard. Returns null if invalid.
 */
function parseSegmentsFromClipboard(json: string): Segment[] | null {
  try {
    const parsed: unknown = JSON.parse(json)
    if (!Array.isArray(parsed)) return null

    // Validate each segment has the expected shape
    const segments: Segment[] = []
    for (const item of parsed) {
      if (!isRecord(item)) return null

      if (item.type === 'text' && typeof item.text === 'string') {
        segments.push({ type: 'text', text: item.text })
      } else if (
        item.type === 'chip' &&
        typeof item.trigger === 'string' &&
        typeof item.value === 'string' &&
        typeof item.displayText === 'string'
      ) {
        const chip: ChipSegment = {
          type: 'chip',
          trigger: item.trigger,
          value: item.value,
          displayText: item.displayText,
          ...(item.data !== undefined ? { data: item.data } : {}),
          ...(item.autoResolved ? { autoResolved: true } : {}),
        }
        segments.push(chip)
      } else {
        return null
      }
    }

    return segments
  } catch {
    return null
  }
}

/**
 * Inserts pasted segments at the current cursor position within existing segments.
 * Splits the text segment at the cursor to insert the pasted content.
 */
function insertSegmentsAtCursor(
  currentSegments: Segment[],
  pastedSegments: Segment[],
  editor: HTMLElement,
): Segment[] {
  // Get cursor offset in the editor
  const range = getSelectionRange()
  if (!range) return [...currentSegments, ...pastedSegments]

  const preRange = document.createRange()
  preRange.selectNodeContents(editor)
  preRange.setEnd(range.startContainer, range.startOffset)

  // Calculate character offset by walking the pre-range fragment
  let cursorOffset = 0
  const fragment = preRange.cloneContents()
  const walk = (node: Node): void => {
    if (node.nodeType === Node.TEXT_NODE) {
      cursorOffset += (node.textContent ?? '').length
    } else if (isChipElement(node)) {
      const trigger = node.dataset.chipTrigger ?? ''
      const display = node.dataset.chipDisplay ?? node.textContent ?? ''
      cursorOffset += trigger.length + display.length
    } else if (isHTMLElement(node) && node.tagName === 'BR') {
      cursorOffset += 1
    } else {
      node.childNodes.forEach(walk)
    }
  }
  fragment.childNodes.forEach(walk)

  // Split current segments at cursor offset and insert pasted segments
  const result: Segment[] = []
  let offset = 0

  for (const seg of currentSegments) {
    if (seg.type === 'chip') {
      const chipLen = seg.trigger.length + seg.displayText.length
      if (offset + chipLen <= cursorOffset) {
        result.push(seg)
      } else if (offset >= cursorOffset) {
        // Will be added after pasted segments
        break
      }
      offset += chipLen
    } else {
      if (offset + seg.text.length <= cursorOffset) {
        result.push(seg)
        offset += seg.text.length
      } else if (offset >= cursorOffset) {
        break
      } else {
        // Split this text segment at cursor
        const splitAt = cursorOffset - offset
        const before = seg.text.slice(0, splitAt)
        if (before) {
          result.push({ type: 'text', text: before })
        }
        offset += seg.text.length
        break
      }
    }
  }

  // Insert pasted segments
  result.push(...pastedSegments)

  // Add remaining segments after cursor
  let pastCursor = false
  let remaining = 0
  for (const seg of currentSegments) {
    if (seg.type === 'chip') {
      const chipLen = seg.trigger.length + seg.displayText.length
      if (remaining + chipLen > cursorOffset) {
        if (pastCursor) {
          result.push(seg)
        } else {
          pastCursor = true
        }
      }
      remaining += chipLen
    } else {
      if (remaining >= cursorOffset) {
        if (pastCursor) {
          result.push(seg)
        } else {
          // This text segment was split — add the remainder
          const splitAt = cursorOffset - remaining
          if (splitAt < 0) {
            result.push(seg)
          } else {
            const after = seg.text.slice(cursorOffset - remaining)
            if (after) {
              result.push({ type: 'text', text: after })
            }
          }
          pastCursor = true
        }
      }
      remaining += seg.text.length
    }
  }

  // Merge adjacent text segments
  const merged: Segment[] = []
  for (const seg of result) {
    if (seg.type === 'text' && seg.text === '') continue
    const last = merged[merged.length - 1]
    if (seg.type === 'text' && last?.type === 'text') {
      merged[merged.length - 1] = { type: 'text', text: last.text + seg.text }
    } else {
      merged.push(seg)
    }
  }

  return merged
}

/**
 * Pure logic engine for the PromptArea component.
 * No DOM dependencies - fully testable in Node.
 */
import type { Segment, ChipSegment, TriggerConfig, TriggerPosition, ActiveTrigger } from './types'

// ---------------------------------------------------------------------------
// Serialization
// ---------------------------------------------------------------------------

/**
 * Converts an array of segments to a plain text string.
 * Chips are represented as `{trigger}{displayText}` (e.g., "@Alice").
 */
export function segmentsToPlainText(segments: Segment[]): string {
  return segments
    .map((seg) => {
      if (seg.type === 'text') return seg.text
      return `${seg.trigger}${seg.displayText}`
    })
    .join('')
}

/**
 * Converts plain text into a single text segment.
 * Used for initial value conversion from plain strings.
 */
export function plainTextToSegments(text: string): Segment[] {
  if (!text) return []
  return [{ type: 'text', text }]
}

// ---------------------------------------------------------------------------
// Trigger position validation
// ---------------------------------------------------------------------------

/**
 * Checks whether a trigger character at the given position in text
 * is valid according to the position rule.
 *
 * @param text - The full text content
 * @param charIndex - The index of the trigger character in the text
 * @param position - The position rule to validate against
 */
export function isValidTriggerPosition(
  text: string,
  charIndex: number,
  position: TriggerPosition,
): boolean {
  if (charIndex === 0) return true

  const prevChar = text[charIndex - 1]

  if (position === 'start') {
    return prevChar === '\n'
  }

  // position === 'any': valid after any whitespace
  return prevChar === ' ' || prevChar === '\n' || prevChar === '\t'
}

// ---------------------------------------------------------------------------
// Trigger detection
// ---------------------------------------------------------------------------

/**
 * Scans backwards from the cursor position to detect if the user is
 * currently typing a trigger word.
 *
 * Returns the active trigger info, or null if no trigger is active.
 *
 * @param text - The full plain text content
 * @param cursorPos - The cursor position (character offset from start)
 * @param triggers - Available trigger configurations
 */
export function detectActiveTrigger(
  text: string,
  cursorPos: number,
  triggers: TriggerConfig[],
): ActiveTrigger | null {
  if (!text || cursorPos === 0 || triggers.length === 0) return null

  // Scan backwards from cursor to find the nearest trigger character.
  // Stop at whitespace (trigger word has ended) or start of text.
  for (let i = cursorPos - 1; i >= 0; i--) {
    const char = text[i]

    // If we hit whitespace before finding a trigger, check if this whitespace
    // is immediately followed by a trigger character
    if (char === ' ' || char === '\n' || char === '\t') {
      // The character after this whitespace could be a trigger
      if (i + 1 < cursorPos) {
        const nextChar = text[i + 1]
        const matchingTrigger = triggers.find((t) => t.char === nextChar)
        if (matchingTrigger && isValidTriggerPosition(text, i + 1, matchingTrigger.position)) {
          return {
            config: matchingTrigger,
            startOffset: i + 1,
            query: text.slice(i + 2, cursorPos),
          }
        }
      }
      // No trigger found after this whitespace, stop searching
      return null
    }

    // Check if this character is a trigger character
    const matchingTrigger = triggers.find((t) => t.char === char)
    if (matchingTrigger && isValidTriggerPosition(text, i, matchingTrigger.position)) {
      return {
        config: matchingTrigger,
        startOffset: i,
        query: text.slice(i + 1, cursorPos),
      }
    }
  }

  return null
}

// ---------------------------------------------------------------------------
// Chip resolution
// ---------------------------------------------------------------------------

/**
 * Resolves an active trigger into a chip within the segments array.
 * Replaces the trigger text (trigger char + query) with a chip segment.
 *
 * @param segments - Current document segments
 * @param activeTrigger - The active trigger to resolve
 * @param chip - The chip data (value, displayText, optional data)
 * @returns New segments array with the chip inserted, and the new cursor position
 */
export function resolveChip(
  segments: Segment[],
  activeTrigger: ActiveTrigger,
  chip: { value: string; displayText: string; data?: unknown; autoResolved?: boolean },
): { segments: Segment[]; cursorOffset: number } {
  const triggerStart = activeTrigger.startOffset
  const triggerEnd = triggerStart + 1 + activeTrigger.query.length // +1 for trigger char

  // Build the new segments by mapping plain text positions back to segment boundaries
  const newSegments: Segment[] = []
  let offset = 0

  for (const seg of segments) {
    if (seg.type === 'chip') {
      const chipText = `${seg.trigger}${seg.displayText}`
      const chipStart = offset
      const chipEnd = offset + chipText.length

      // If the trigger range overlaps with this chip, something is wrong.
      // Chips should not be partially replaced.
      if (chipEnd <= triggerStart || chipStart >= triggerEnd) {
        newSegments.push(seg)
      }
      offset = chipEnd
    } else {
      const textStart = offset
      const textEnd = offset + seg.text.length

      if (textEnd <= triggerStart) {
        // Entirely before the trigger - keep as-is
        newSegments.push(seg)
      } else if (textStart >= triggerEnd) {
        // Entirely after the trigger - keep as-is
        newSegments.push(seg)
      } else {
        // This text segment contains (part of) the trigger range
        const beforeText = seg.text.slice(0, Math.max(0, triggerStart - textStart))
        const afterText = seg.text.slice(Math.min(seg.text.length, triggerEnd - textStart))

        if (beforeText) {
          newSegments.push({ type: 'text', text: beforeText })
        }

        const newChip: ChipSegment = {
          type: 'chip',
          trigger: activeTrigger.config.char,
          value: chip.value,
          displayText: chip.displayText,
          ...(chip.data !== undefined ? { data: chip.data } : {}),
          ...(chip.autoResolved ? { autoResolved: true } : {}),
        }
        newSegments.push(newChip)

        // Add trailing space after chip, then any remaining text
        if (afterText) {
          newSegments.push({ type: 'text', text: ' ' + afterText.replace(/^\s/, '') })
        } else {
          newSegments.push({ type: 'text', text: ' ' })
        }
      }

      offset = textEnd
    }
  }

  // Merge adjacent text segments
  const merged = mergeAdjacentTextSegments(newSegments)

  // Cursor should be placed after the chip + trailing space.
  // Find the *last* matching chip so duplicates resolve correctly.
  let lastChipEndOffset = -1
  let runningOffset = 0
  for (const seg of merged) {
    if (seg.type === 'text') {
      runningOffset += seg.text.length
    } else {
      runningOffset += seg.trigger.length + seg.displayText.length
      if (
        seg.value === chip.value &&
        seg.displayText === chip.displayText &&
        seg.trigger === activeTrigger.config.char
      ) {
        lastChipEndOffset = runningOffset
      }
    }
  }
  // +1 accounts for the trailing space after the chip
  const cursorOffset = lastChipEndOffset === -1 ? runningOffset : lastChipEndOffset + 1

  return { segments: merged, cursorOffset }
}

// ---------------------------------------------------------------------------
// Chip removal
// ---------------------------------------------------------------------------

/**
 * Removes a chip at the given segment index and merges adjacent text segments.
 *
 * @param segments - Current document segments
 * @param index - The segment index to remove
 * @returns New segments array with the chip removed
 */
export function removeChipAtIndex(segments: Segment[], index: number): Segment[] {
  if (index < 0 || index >= segments.length) return segments
  if (segments[index].type !== 'chip') return segments

  const result = [...segments.slice(0, index), ...segments.slice(index + 1)]
  return mergeAdjacentTextSegments(result)
}

/**
 * Reverts an auto-resolved chip at the given segment index back to plain text.
 * The text includes the trigger character + display text (e.g., "#readme").
 *
 * @param segments - Current document segments
 * @param index - The segment index to revert
 * @returns New segments with the chip replaced by text, or null if not applicable
 */
export function revertChipAtIndex(
  segments: Segment[],
  index: number,
): { segments: Segment[]; revertedText: string } | null {
  if (index < 0 || index >= segments.length) return null
  const seg = segments[index]
  if (seg.type !== 'chip' || !seg.autoResolved) return null

  const revertedText = `${seg.trigger}${seg.displayText}`
  const result = [
    ...segments.slice(0, index),
    { type: 'text' as const, text: revertedText },
    ...segments.slice(index + 1),
  ]
  return { segments: mergeAdjacentTextSegments(result), revertedText }
}

// ---------------------------------------------------------------------------
// Paste: resolve trigger patterns in segments
// ---------------------------------------------------------------------------

/**
 * Scans text segments for trigger patterns and auto-resolves them into chips.
 * Only resolves triggers that have `resolveOnSpace: true`.
 *
 * Trigger patterns must appear at word boundaries: start of text, after
 * whitespace, or after a newline. This avoids false positives like email
 * addresses (user@example.com).
 *
 * @param segments - The segments to scan
 * @param triggers - Available trigger configurations
 * @returns New segments with matched trigger patterns resolved to chips
 */
export function resolveTriggersInSegments(
  segments: Segment[],
  triggers: TriggerConfig[],
): Segment[] {
  const autoResolveTriggers = triggers.filter((t) => t.resolveOnSpace)
  if (autoResolveTriggers.length === 0) return segments

  // Build a set of trigger chars for fast lookup
  const triggerChars = new Set(autoResolveTriggers.map((t) => t.char))

  const result: Segment[] = []

  for (const seg of segments) {
    if (seg.type === 'chip') {
      result.push(seg)
      continue
    }

    const parts = splitTextByTriggerPatterns(seg.text, autoResolveTriggers, triggerChars)
    result.push(...parts)
  }

  return mergeAdjacentTextSegments(result)
}

/**
 * Splits a text string into text and chip segments based on trigger patterns.
 * A trigger pattern is: (start-of-string | whitespace) + trigger_char + word_chars
 * followed by whitespace or end-of-string.
 */
function splitTextByTriggerPatterns(
  text: string,
  triggers: TriggerConfig[],
  triggerChars: Set<string>,
): Segment[] {
  if (!text) return []

  const segments: Segment[] = []
  let i = 0

  while (i < text.length) {
    const char = text[i]

    if (triggerChars.has(char)) {
      // Check if this trigger char is at a valid position
      const isAtBoundary =
        i === 0 || text[i - 1] === ' ' || text[i - 1] === '\n' || text[i - 1] === '\t'

      if (isAtBoundary) {
        const trigger = triggers.find((t) => t.char === char)
        if (trigger && isValidTriggerPosition(text, i, trigger.position)) {
          // Scan forward for the word (non-whitespace characters)
          let end = i + 1
          while (
            end < text.length &&
            text[end] !== ' ' &&
            text[end] !== '\n' &&
            text[end] !== '\t'
          ) {
            end++
          }

          const query = text.slice(i + 1, end)
          if (query.length > 0) {
            // Create a chip segment
            const displayText = trigger.onSelect?.({ value: query, label: query }) ?? query
            segments.push({
              type: 'chip',
              trigger: char,
              value: query,
              displayText: displayText || query,
              autoResolved: true,
            })
            i = end
            continue
          }
        }
      }
    }

    // Not a trigger pattern — accumulate as text
    const start = i
    i++
    while (
      i < text.length &&
      !(
        triggerChars.has(text[i]) &&
        (i === 0 || text[i - 1] === ' ' || text[i - 1] === '\n' || text[i - 1] === '\t')
      )
    ) {
      i++
    }
    segments.push({ type: 'text', text: text.slice(start, i) })
  }

  return segments
}

// ---------------------------------------------------------------------------
// Text range replacement (used by list functions)
// ---------------------------------------------------------------------------

/**
 * Replaces a range of plain text within the segments array.
 * Handles segment boundaries correctly, preserving chip segments.
 *
 * @param segments - Current document segments
 * @param start - Start offset in plain text
 * @param end - End offset in plain text
 * @param replacement - The replacement text
 * @returns New segments array with the replacement applied
 */
export function replaceTextRange(
  segments: Segment[],
  start: number,
  end: number,
  replacement: string,
): Segment[] {
  const newSegments: Segment[] = []
  let offset = 0
  let inserted = false

  for (const seg of segments) {
    if (seg.type === 'chip') {
      const chipText = `${seg.trigger}${seg.displayText}`
      const chipStart = offset
      const chipEnd = offset + chipText.length

      // For insertion (start === end), insert before this chip if position matches
      if (!inserted && start === end && chipStart === start) {
        newSegments.push({ type: 'text', text: replacement })
        inserted = true
      }

      if (chipEnd <= start || chipStart >= end) {
        newSegments.push(seg)
      }
      // Chips within the range are removed
      offset = chipEnd
    } else {
      const textStart = offset
      const textEnd = offset + seg.text.length

      // Check if this segment contains the insertion/replacement point
      const isBefore = start === end ? textEnd < start : textEnd <= start
      const isAfter = start === end ? textStart > end : textStart >= end

      if (isBefore) {
        // Entirely before the range
        newSegments.push(seg)
      } else if (isAfter) {
        // Entirely after the range
        newSegments.push(seg)
      } else {
        // Overlaps with the range (or contains the insertion point)
        const beforeText = seg.text.slice(0, Math.max(0, start - textStart))
        const afterText = seg.text.slice(Math.min(seg.text.length, end - textStart))

        if (beforeText) {
          newSegments.push({ type: 'text', text: beforeText })
        }
        // Insert replacement only once (when we first enter the range)
        if (!inserted && textStart <= start) {
          newSegments.push({ type: 'text', text: replacement })
          inserted = true
        }
        if (afterText) {
          newSegments.push({ type: 'text', text: afterText })
        }
      }

      offset = textEnd
    }
  }

  // Fallback: if replacement wasn't inserted (e.g., insertion at very end)
  if (!inserted && replacement) {
    newSegments.push({ type: 'text', text: replacement })
  }

  return mergeAdjacentTextSegments(newSegments)
}

// ---------------------------------------------------------------------------
// Markdown formatting shortcuts
// ---------------------------------------------------------------------------

/**
 * Toggles markdown wrap markers around a selected text range.
 * If the selection is already wrapped with the marker, unwraps it.
 * If not wrapped, wraps it.
 *
 * @param segments - Current document segments
 * @param selectionStart - Start offset in plain text
 * @param selectionEnd - End offset in plain text
 * @param marker - The markdown marker (e.g., '**' for bold, '*' for italic)
 * @returns New segments and selection offsets, or null if selection is collapsed
 */
export function toggleMarkdownWrap(
  segments: Segment[],
  selectionStart: number,
  selectionEnd: number,
  marker: string,
): { segments: Segment[]; selectionStart: number; selectionEnd: number } | null {
  if (selectionStart === selectionEnd) return null

  const plainText = segmentsToPlainText(segments)
  const markerLen = marker.length

  // Check if already wrapped
  const hasOpeningMarker =
    selectionStart >= markerLen &&
    plainText.slice(selectionStart - markerLen, selectionStart) === marker
  const hasClosingMarker =
    selectionEnd + markerLen <= plainText.length &&
    plainText.slice(selectionEnd, selectionEnd + markerLen) === marker

  let isWrapped = hasOpeningMarker && hasClosingMarker

  // For single-char markers (e.g., '*'), ensure we're not matching
  // inside a multi-char marker (e.g., '**')
  if (isWrapped && markerLen === 1) {
    const charBeforeOpening =
      selectionStart > markerLen ? plainText[selectionStart - markerLen - 1] : ''
    const charAfterClosing =
      selectionEnd + markerLen < plainText.length ? plainText[selectionEnd + markerLen] : ''
    if (charBeforeOpening === marker || charAfterClosing === marker) {
      isWrapped = false
    }
  }

  if (isWrapped) {
    // Unwrap: remove closing marker first (preserves start offsets), then opening
    const afterClosing = replaceTextRange(segments, selectionEnd, selectionEnd + markerLen, '')
    const afterOpening = replaceTextRange(
      afterClosing,
      selectionStart - markerLen,
      selectionStart,
      '',
    )
    return {
      segments: afterOpening,
      selectionStart: selectionStart - markerLen,
      selectionEnd: selectionEnd - markerLen,
    }
  }

  // Wrap: insert closing marker first (preserves start offsets), then opening
  const afterClosing = replaceTextRange(segments, selectionEnd, selectionEnd, marker)
  const afterOpening = replaceTextRange(afterClosing, selectionStart, selectionStart, marker)
  return {
    segments: afterOpening,
    selectionStart: selectionStart + markerLen,
    selectionEnd: selectionEnd + markerLen,
  }
}

// ---------------------------------------------------------------------------
// List auto-formatting
// ---------------------------------------------------------------------------

/**
 * Information about a list line at a given cursor position.
 */
export type ListContext = {
  /** Offset in plain text where the line begins */
  lineStart: number
  /** The full prefix including indentation (e.g., "  \u2022 ") */
  prefix: string
  /** Number of indentation levels (each = 2 spaces) */
  indent: number
  /** Type of list */
  listType: 'bullet' | 'numbered'
  /** For numbered lists, the number */
  number?: number
  /** Offset in plain text where content after the prefix starts */
  contentStart: number
}

/**
 * Detects if the cursor is in a list line and returns context about it.
 *
 * @param text - The full plain text content
 * @param cursorPos - The cursor position (character offset from start)
 * @returns List context if the cursor is in a list line, null otherwise
 */
export function getListContext(text: string, cursorPos: number): ListContext | null {
  // Find the start of the current line
  const lineStart = text.lastIndexOf('\n', cursorPos - 1) + 1
  const lineEnd = text.indexOf('\n', cursorPos)
  const line = text.slice(lineStart, lineEnd === -1 ? text.length : lineEnd)

  // Match bullet: (spaces)(bullet_char) (space)
  const bulletMatch = line.match(/^(\s*)([•\-*]) /)
  if (bulletMatch) {
    const indentStr = bulletMatch[1]
    return {
      lineStart,
      prefix: bulletMatch[0],
      indent: Math.floor(indentStr.length / 2),
      listType: 'bullet',
      contentStart: lineStart + bulletMatch[0].length,
    }
  }

  // Match numbered: (spaces)(digits). (space)
  const numberMatch = line.match(/^(\s*)(\d+)\. /)
  if (numberMatch) {
    const indentStr = numberMatch[1]
    return {
      lineStart,
      prefix: numberMatch[0],
      indent: Math.floor(indentStr.length / 2),
      listType: 'numbered',
      number: parseInt(numberMatch[2], 10),
      contentStart: lineStart + numberMatch[0].length,
    }
  }

  return null
}

/**
 * Detects if the user just typed a list trigger pattern (e.g., "- " or "* ")
 * and returns the segments with the replacement applied.
 *
 * @param segments - Current segments
 * @param cursorPos - The cursor position after typing
 * @returns New segments with auto-formatted prefix and new cursor offset, or null
 */
export function autoFormatListPrefix(
  segments: Segment[],
  cursorPos: number,
): { segments: Segment[]; cursorOffset: number } | null {
  const plainText = segmentsToPlainText(segments)
  const lineStart = plainText.lastIndexOf('\n', cursorPos - 1) + 1
  const lineText = plainText.slice(lineStart, cursorPos)

  // Match "- " or "* " (with optional leading spaces) at the end of typed text
  const match = lineText.match(/^(\s*)[-*] $/)
  if (!match) return null

  const indent = match[1]
  const replacement = `${indent}\u2022 `
  const rangeStart = lineStart
  const rangeEnd = lineStart + lineText.length

  const newSegments = replaceTextRange(segments, rangeStart, rangeEnd, replacement)
  return {
    segments: newSegments,
    cursorOffset: lineStart + replacement.length,
  }
}

/**
 * Handles Enter key in a list line — continues the list or exits.
 *
 * @param segments - Current segments
 * @param cursorPos - The cursor position
 * @returns New segments and cursor offset, or null if not in a list
 */
export function insertListContinuation(
  segments: Segment[],
  cursorPos: number,
): { segments: Segment[]; cursorOffset: number } | null {
  const plainText = segmentsToPlainText(segments)
  const ctx = getListContext(plainText, cursorPos)
  if (!ctx) return null

  const lineEnd = plainText.indexOf('\n', cursorPos)
  const lineContent = plainText.slice(ctx.contentStart, lineEnd === -1 ? plainText.length : lineEnd)

  // If the line content (after prefix) is empty, exit list mode
  if (lineContent.trim() === '') {
    // Remove the entire prefix (convert list line to empty line)
    const newSegments = replaceTextRange(
      segments,
      ctx.lineStart,
      ctx.lineStart + ctx.prefix.length,
      '',
    )
    return {
      segments: newSegments,
      cursorOffset: ctx.lineStart,
    }
  }

  // Build the next line prefix
  const indent = '  '.repeat(ctx.indent)
  let nextPrefix: string
  if (ctx.listType === 'bullet') {
    nextPrefix = `${indent}\u2022 `
  } else {
    const nextNum = (ctx.number ?? 1) + 1
    nextPrefix = `${indent}${nextNum}. `
  }

  // Insert newline + next prefix at cursor position
  const insertion = `\n${nextPrefix}`
  const newSegments = replaceTextRange(segments, cursorPos, cursorPos, insertion)
  return {
    segments: newSegments,
    cursorOffset: cursorPos + insertion.length,
  }
}

/**
 * Indents a list item by one level (adds 2 spaces before the prefix).
 *
 * @param segments - Current segments
 * @param cursorPos - The cursor position
 * @returns New segments and cursor offset, or null if not in a list
 */
export function indentListItem(
  segments: Segment[],
  cursorPos: number,
): { segments: Segment[]; cursorOffset: number } | null {
  const plainText = segmentsToPlainText(segments)
  const ctx = getListContext(plainText, cursorPos)
  if (!ctx) return null

  // Insert 2 spaces at the line start
  const newSegments = replaceTextRange(segments, ctx.lineStart, ctx.lineStart, '  ')
  return {
    segments: newSegments,
    cursorOffset: cursorPos + 2,
  }
}

/**
 * Outdents a list item by one level (removes 2 spaces from before the prefix).
 *
 * @param segments - Current segments
 * @param cursorPos - The cursor position
 * @returns New segments and cursor offset, or null if not indented
 */
export function outdentListItem(
  segments: Segment[],
  cursorPos: number,
): { segments: Segment[]; cursorOffset: number } | null {
  const plainText = segmentsToPlainText(segments)
  const ctx = getListContext(plainText, cursorPos)
  if (!ctx || ctx.indent === 0) return null

  // Remove 2 spaces from the line start
  const newSegments = replaceTextRange(segments, ctx.lineStart, ctx.lineStart + 2, '')
  return {
    segments: newSegments,
    cursorOffset: Math.max(ctx.lineStart, cursorPos - 2),
  }
}

/**
 * Removes the list prefix from the current line (e.g., on Backspace).
 *
 * @param segments - Current segments
 * @param cursorPos - The cursor position
 * @returns New segments and cursor offset, or null if not at prefix boundary
 */
export function removeListPrefix(
  segments: Segment[],
  cursorPos: number,
): { segments: Segment[]; cursorOffset: number } | null {
  const plainText = segmentsToPlainText(segments)
  const ctx = getListContext(plainText, cursorPos)
  if (!ctx) return null

  // Only act if cursor is at or before the content start
  if (cursorPos > ctx.contentStart) return null

  // Remove the prefix (keep indentation + content after prefix)
  const newSegments = replaceTextRange(
    segments,
    ctx.lineStart,
    ctx.contentStart,
    '  '.repeat(ctx.indent),
  )
  return {
    segments: newSegments,
    cursorOffset: ctx.lineStart + ctx.indent * 2,
  }
}

// ---------------------------------------------------------------------------
// Inline markdown parsing
// ---------------------------------------------------------------------------

export type MarkdownToken =
  | { type: 'plain'; text: string }
  | { type: 'bold'; text: string }
  | { type: 'italic'; text: string }
  | { type: 'bold-italic'; text: string }
  | { type: 'url'; text: string }

/**
 * Parses text for simple inline markdown: bold, italic, bold-italic, and URLs.
 * Does NOT handle block-level markdown (lists, headings, etc.).
 */
export function parseInlineMarkdown(text: string): MarkdownToken[] {
  if (!text) return []

  const tokens: MarkdownToken[] = []
  // Regex patterns for inline markdown elements:
  // 1. ***text*** or ___text___ -> bold-italic
  // 2. **text** or __text__   -> bold
  // 3. *text* or _text_       -> italic
  // 4. https://... or http://... -> URL
  const pattern = /(\*{3}(.+?)\*{3})|(\*{2}(.+?)\*{2})|(\*(.+?)\*)|(https?:\/\/[^\s),]+)/g

  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = pattern.exec(text)) !== null) {
    // Add any plain text before this match
    if (match.index > lastIndex) {
      tokens.push({ type: 'plain', text: text.slice(lastIndex, match.index) })
    }

    if (match[1] && match[2]) {
      // ***bold-italic***
      tokens.push({ type: 'bold-italic', text: match[2] })
    } else if (match[3] && match[4]) {
      // **bold**
      tokens.push({ type: 'bold', text: match[4] })
    } else if (match[5] && match[6]) {
      // *italic*
      tokens.push({ type: 'italic', text: match[6] })
    } else if (match[7]) {
      // URL
      tokens.push({ type: 'url', text: match[7] })
    }

    lastIndex = match.index + match[0].length
  }

  // Add any remaining plain text
  if (lastIndex < text.length) {
    tokens.push({ type: 'plain', text: text.slice(lastIndex) })
  }

  return tokens
}

// ---------------------------------------------------------------------------
// Segment comparison
// ---------------------------------------------------------------------------

/**
 * Shallow equality check for two segment arrays.
 * Compares type, text, trigger, value, displayText, and autoResolved fields.
 * Avoids JSON.stringify overhead for the common case.
 */
export function segmentsEqual(a: Segment[], b: Segment[]): boolean {
  if (a === b) return true
  if (a.length !== b.length) return false

  for (let i = 0; i < a.length; i++) {
    const sa = a[i]
    const sb = b[i]
    if (sa.type !== sb.type) return false
    if (sa.type === 'text') {
      if (sb.type !== 'text' || sa.text !== sb.text) return false
    } else {
      if (
        sb.type !== 'chip' ||
        sa.trigger !== sb.trigger ||
        sa.value !== sb.value ||
        sa.displayText !== sb.displayText ||
        sa.autoResolved !== sb.autoResolved
      )
        return false
    }
  }
  return true
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Merges adjacent text segments into single text segments.
 * Also removes empty text segments.
 */
function mergeAdjacentTextSegments(segments: Segment[]): Segment[] {
  const result: Segment[] = []

  for (const seg of segments) {
    if (seg.type === 'text' && seg.text === '') continue

    const last = result[result.length - 1]
    if (seg.type === 'text' && last?.type === 'text') {
      // Merge with previous text segment
      result[result.length - 1] = { type: 'text', text: last.text + seg.text }
    } else {
      result.push(seg)
    }
  }

  return result
}

/**
 * Type-safe DOM helper functions for PromptArea.
 *
 * These replace all `as` type assertions with proper type guards,
 * following the codebase rule: "Never use `any` or `as` assertions."
 */

// ---------------------------------------------------------------------------
// Type Guards
// ---------------------------------------------------------------------------

/**
 * Type guard: checks if a DOM node is an HTMLElement.
 */
export function isHTMLElement(node: Node): node is HTMLElement {
  return node instanceof HTMLElement
}

/**
 * Type guard: checks if a DOM node is a chip element
 * (an HTMLElement with data-chip-trigger attribute).
 */
export function isChipElement(node: Node): node is HTMLElement {
  return node instanceof HTMLElement && node.dataset.chipTrigger !== undefined
}

/**
 * Type guard: checks if a DOM node is a BR element.
 */
export function isBRElement(node: Node): node is HTMLBRElement {
  return node instanceof HTMLBRElement
}

/**
 * Type guard: checks if a DOM node is a Text node.
 */
export function isTextNode(node: Node): node is Text {
  return node instanceof Text
}

/**
 * Checks whether a chip element was auto-resolved (created by pressing space
 * on resolveOnSpace triggers, rather than explicit dropdown selection).
 */
export function getChipAutoResolved(node: Node): boolean {
  return isChipElement(node) && node.dataset.chipAutoResolved === 'true'
}

/**
 * Type guard: checks if a DOM node is a URL link element
 * (an HTMLAnchorElement with data-url attribute).
 */
export function isLinkElement(node: Node): node is HTMLAnchorElement {
  return node instanceof HTMLAnchorElement && node.dataset.url === 'true'
}

// ---------------------------------------------------------------------------
// Safe JSON
// ---------------------------------------------------------------------------

/**
 * Safely parses a JSON string, returning `unknown` instead of `any`.
 * Returns `undefined` if parsing fails.
 */
export function safeJsonParse(json: string): unknown {
  try {
    // JSON.parse returns `any` by default. We narrow it to `unknown`
    // which is the safest pattern — callers must validate before use.
    const parsed: unknown = JSON.parse(json)
    return parsed
  } catch {
    return undefined
  }
}

/**
 * Safely serializes a value to JSON, returning undefined on failure.
 */
export function safeJsonStringify(value: unknown): string | undefined {
  try {
    return JSON.stringify(value)
  } catch {
    return undefined
  }
}

// ---------------------------------------------------------------------------
// DOM reading helpers
// ---------------------------------------------------------------------------

/**
 * Reads the chip trigger character from a chip element's dataset.
 * Returns undefined if the node is not a chip element.
 */
export function getChipTrigger(node: Node): string | undefined {
  if (!isChipElement(node)) return undefined
  return node.dataset.chipTrigger
}

/**
 * Reads the chip value from a chip element's dataset.
 */
export function getChipValue(node: Node): string | undefined {
  if (!isChipElement(node)) return undefined
  return node.dataset.chipValue
}

/**
 * Reads the chip display text from a chip element's dataset.
 */
export function getChipDisplay(node: Node): string | undefined {
  if (!isChipElement(node)) return undefined
  return node.dataset.chipDisplay ?? node.textContent ?? undefined
}

/**
 * Reads and safely parses the chip data from a chip element's dataset.
 */
export function getChipData(node: Node): unknown {
  if (!isChipElement(node)) return undefined
  const raw = node.dataset.chipData
  if (!raw) return undefined
  return safeJsonParse(raw)
}

// ---------------------------------------------------------------------------
// DOM manipulation helpers
// ---------------------------------------------------------------------------

/**
 * Finds the index of a direct child node within a parent element.
 * Returns -1 if not found.
 */
export function indexOfChildNode(parent: HTMLElement, child: Node): number {
  const children = parent.childNodes
  for (let i = 0; i < children.length; i++) {
    if (children[i] === child) return i
  }
  return -1
}

/**
 * Gets the direct child of `ancestor` that contains `descendant`.
 * Walks up from descendant until we find a node whose parent is ancestor.
 * Returns null if descendant is not inside ancestor.
 */
export function getDirectChildContaining(ancestor: HTMLElement, descendant: Node): Node | null {
  let node: Node | null = descendant
  while (node !== null) {
    if (node.parentNode === ancestor) return node
    node = node.parentNode
  }
  return null
}

/**
 * Unwraps a block element (div, p) by replacing it with its child nodes
 * plus a trailing BR. Used for browser DOM normalization.
 */
export function unwrapBlockElement(parent: HTMLElement, block: HTMLElement): void {
  const fragment = document.createDocumentFragment()

  // Move all children to fragment
  while (block.firstChild) {
    fragment.appendChild(block.firstChild)
  }

  // Add a BR after the unwrapped content
  fragment.appendChild(document.createElement('br'))

  parent.replaceChild(fragment, block)
}

/**
 * Normalizes the editor DOM after browser mutations.
 *
 * Browsers insert various wrapper elements on Enter/paste:
 * - Chrome wraps new lines in <div>
 * - Safari may use <div><br></div>
 * - Some use <p> tags
 *
 * This function unwraps all non-chip block elements, leaving only:
 * - Text nodes
 * - <br> elements
 * - Chip <span> elements (with data-chip-trigger)
 */
export function normalizeEditorDOM(editor: HTMLElement): boolean {
  let changed = false
  const blockTags = new Set(['DIV', 'P', 'SECTION', 'ARTICLE', 'BLOCKQUOTE'])

  // Iterate backwards since we're modifying the DOM
  for (let i = editor.childNodes.length - 1; i >= 0; i--) {
    const child = editor.childNodes[i]

    // Skip non-element nodes, chip elements, and BR elements
    if (!(child instanceof HTMLElement)) continue
    if (child.dataset.chipTrigger !== undefined) continue
    if (child instanceof HTMLBRElement) continue

    const tag = child.tagName
    if (blockTags.has(tag)) {
      unwrapBlockElement(editor, child)
      changed = true
    } else if (
      tag === 'FONT' ||
      tag === 'B' ||
      tag === 'I' ||
      tag === 'U' ||
      tag === 'STRONG' ||
      tag === 'EM' ||
      tag === 'A' ||
      tag === 'SPAN'
    ) {
      // Unwrap inline formatting/decoration elements (browser-inserted or markdown decorations)
      const text = child.textContent ?? ''
      if (text) {
        editor.replaceChild(document.createTextNode(text), child)
      } else {
        editor.removeChild(child)
      }
      changed = true
    }
  }

  // Merge adjacent text nodes
  editor.normalize()

  return changed
}

// ---------------------------------------------------------------------------
// URL decoration
// ---------------------------------------------------------------------------

/** URL pattern for detecting URLs in text content */
const URL_PATTERN = /https?:\/\/[^\s),]+/g

/**
 * Walks direct-child text nodes in the editor and wraps URL text in
 * `<a>` elements for visual styling and clickability.
 *
 * This is a DOM-only decoration — it does NOT modify the segment model.
 * The `<a>` elements are stripped by `normalizeEditorDOM` on every input cycle,
 * so they are re-applied fresh each time.
 *
 * @param editor - The contentEditable root element
 * @returns Whether any decorations were applied
 */
export function decorateURLsInEditor(editor: HTMLElement): boolean {
  let decorated = false

  // Collect text nodes first (avoid modifying while iterating)
  const textNodes: Text[] = []
  for (let i = 0; i < editor.childNodes.length; i++) {
    const node = editor.childNodes[i]
    if (isTextNode(node) && node.textContent) {
      textNodes.push(node)
    }
  }

  for (const textNode of textNodes) {
    const text = textNode.textContent ?? ''
    URL_PATTERN.lastIndex = 0
    const matches: Array<{ url: string; index: number }> = []
    let match: RegExpExecArray | null

    while ((match = URL_PATTERN.exec(text)) !== null) {
      // Trim trailing punctuation that's likely not part of the URL
      let url = match[0]
      while (url.length > 0 && /[.;:!?]$/.test(url)) {
        url = url.slice(0, -1)
      }
      if (url.length > 0) {
        matches.push({ url, index: match.index })
      }
    }

    if (matches.length === 0) continue

    decorated = true
    const parent = textNode.parentNode
    if (!parent) continue

    const fragment = document.createDocumentFragment()
    let lastIndex = 0

    for (const { url, index } of matches) {
      // Text before this URL
      if (index > lastIndex) {
        fragment.appendChild(document.createTextNode(text.slice(lastIndex, index)))
      }

      // Create the link element
      const anchor = document.createElement('a')
      anchor.href = url
      anchor.target = '_blank'
      anchor.rel = 'noopener noreferrer'
      anchor.dataset.url = 'true'
      anchor.className = 'text-primary hover:text-primary/80 underline cursor-pointer'
      anchor.textContent = url
      fragment.appendChild(anchor)

      lastIndex = index + url.length
    }

    // Text after the last URL
    if (lastIndex < text.length) {
      fragment.appendChild(document.createTextNode(text.slice(lastIndex)))
    }

    parent.replaceChild(fragment, textNode)
  }

  return decorated
}

// ---------------------------------------------------------------------------
// Markdown inline decoration
// ---------------------------------------------------------------------------

/** Pattern to find ***bold-italic***, **bold**, and *italic* markdown spans */
const MARKDOWN_INLINE_PATTERN = /(\*{3})(.+?)\*{3}|(\*{2})(.+?)\*{2}|(\*)(.+?)\*/g

/**
 * Walks direct-child text nodes in the editor and wraps markdown-formatted
 * text (`**bold**`, `*italic*`, `***bold-italic***`) in styled `<span>` elements.
 *
 * This is a DOM-only decoration — it does NOT modify the segment model.
 * The `<span>` elements are stripped by `normalizeEditorDOM` on every input cycle,
 * so they are re-applied fresh each time.
 *
 * The `*` markers stay visible in the text; only the CSS styling changes.
 *
 * @param editor - The contentEditable root element
 * @returns Whether any decorations were applied
 */
export function decorateMarkdownInEditor(editor: HTMLElement): boolean {
  let decorated = false

  // Collect text nodes first (avoid modifying while iterating)
  const textNodes: Text[] = []
  for (let i = 0; i < editor.childNodes.length; i++) {
    const node = editor.childNodes[i]
    if (isTextNode(node) && node.textContent) {
      textNodes.push(node)
    }
  }

  for (const textNode of textNodes) {
    const text = textNode.textContent ?? ''
    MARKDOWN_INLINE_PATTERN.lastIndex = 0
    const matches: Array<{
      fullMatch: string
      marker: string
      content: string
      index: number
      className: string
    }> = []
    let match: RegExpExecArray | null

    while ((match = MARKDOWN_INLINE_PATTERN.exec(text)) !== null) {
      if (match[1] && match[2]) {
        // ***bold-italic***
        matches.push({
          fullMatch: match[0],
          marker: match[1],
          content: match[2],
          index: match.index,
          className: 'font-bold italic',
        })
      } else if (match[3] && match[4]) {
        // **bold**
        matches.push({
          fullMatch: match[0],
          marker: match[3],
          content: match[4],
          index: match.index,
          className: 'font-bold',
        })
      } else if (match[5] && match[6]) {
        // *italic*
        matches.push({
          fullMatch: match[0],
          marker: match[5],
          content: match[6],
          index: match.index,
          className: 'italic',
        })
      }
    }

    if (matches.length === 0) continue

    decorated = true
    const parent = textNode.parentNode
    if (!parent) continue

    const fragment = document.createDocumentFragment()
    let lastIndex = 0

    for (const { fullMatch, marker, content, index, className } of matches) {
      // Text before this match
      if (index > lastIndex) {
        fragment.appendChild(document.createTextNode(text.slice(lastIndex, index)))
      }

      // Parent span — textContent still returns full match (e.g. "**world**")
      const span = document.createElement('span')
      span.dataset.md = 'true'

      // Opening marker (visually hidden)
      const openMarker = document.createElement('span')
      openMarker.className = 'prompt-area-md-marker'
      openMarker.textContent = marker

      // Styled content
      const styledContent = document.createElement('span')
      styledContent.className = className
      styledContent.textContent = content

      // Closing marker (visually hidden)
      const closeMarker = document.createElement('span')
      closeMarker.className = 'prompt-area-md-marker'
      closeMarker.textContent = marker

      span.appendChild(openMarker)
      span.appendChild(styledContent)
      span.appendChild(closeMarker)
      fragment.appendChild(span)

      lastIndex = index + fullMatch.length
    }

    // Text after the last match
    if (lastIndex < text.length) {
      fragment.appendChild(document.createTextNode(text.slice(lastIndex)))
    }

    parent.replaceChild(fragment, textNode)
  }

  return decorated
}

// ---------------------------------------------------------------------------
// Selection helpers
// ---------------------------------------------------------------------------

/**
 * Returns the first Range from the current window selection, or null if
 * there is no selection or it has no ranges.
 */
export function getSelectionRange(): Range | null {
  const sel = window.getSelection()
  if (!sel || sel.rangeCount === 0) return null
  return sel.getRangeAt(0)
}

'use client'

import { useCallback, useEffect, useRef, useState } from 'react'
import type { TriggerConfig, TriggerSuggestion } from './types'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type UseTriggerSearchReturn = {
  suggestions: TriggerSuggestion[]
  suggestionsLoading: boolean
  suggestionsError: string | null
  /** Run a search for the given query using the trigger's onSearch config. */
  search: (query: string, config: TriggerConfig) => void
  /** Cancel any in-flight search and reset state. */
  reset: () => void
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages async trigger search lifecycle: debouncing, AbortController
 * cancellation, race-condition prevention, loading/error state.
 *
 * Extracted from `usePromptArea` so the main hook stays focused on
 * editing concerns while this hook owns the data-fetching side.
 */
export function useTriggerSearch(): UseTriggerSearchReturn {
  const [suggestions, setSuggestions] = useState<TriggerSuggestion[]>([])
  const [suggestionsLoading, setSuggestionsLoading] = useState(false)
  const [suggestionsError, setSuggestionsError] = useState<string | null>(null)

  // Version counter – belt-and-suspenders alongside AbortController
  const searchVersion = useRef(0)
  // AbortController for cancelling in-flight async searches
  const abortController = useRef<AbortController | null>(null)
  // Debounce timer for search queries
  const debounceTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const reset = useCallback(() => {
    abortController.current?.abort()
    if (debounceTimer.current) clearTimeout(debounceTimer.current)
    setSuggestions([])
    setSuggestionsLoading(false)
    setSuggestionsError(null)
  }, [])

  const search = useCallback((query: string, config: TriggerConfig) => {
    if (!config.onSearch) return

    // Cancel any previous in-flight request and pending debounce
    abortController.current?.abort()
    if (debounceTimer.current) clearTimeout(debounceTimer.current)

    setSuggestionsLoading(true)
    setSuggestionsError(null)
    searchVersion.current++
    const version = searchVersion.current

    const controller = new AbortController()
    abortController.current = controller
    const { onSearch, onSearchError, searchDebounceMs } = config

    const executeSearch = () => {
      const result = onSearch(query, { signal: controller.signal })

      if (result instanceof Promise) {
        void result.then(
          (items) => {
            if (controller.signal.aborted || searchVersion.current !== version) return
            setSuggestions(items)
            setSuggestionsLoading(false)
          },
          (error: unknown) => {
            if (controller.signal.aborted || searchVersion.current !== version) return
            // Silently ignore AbortError (expected when superseded)
            if (error instanceof DOMException && error.name === 'AbortError') return
            setSuggestionsError(error instanceof Error ? error.message : 'Search failed')
            setSuggestionsLoading(false)
            onSearchError?.(error)
          },
        )
      } else {
        setSuggestions(result)
        setSuggestionsLoading(false)
      }
    }

    // Debounce subsequent searches but fire immediately for the initial empty query
    if (searchDebounceMs && searchDebounceMs > 0 && query.length > 0) {
      debounceTimer.current = setTimeout(executeSearch, searchDebounceMs)
    } else {
      executeSearch()
    }
  }, [])

  // Clean up on unmount
  useEffect(() => {
    return () => {
      abortController.current?.abort()
      if (debounceTimer.current) clearTimeout(debounceTimer.current)
    }
  }, [])

  return {
    suggestions,
    suggestionsLoading,
    suggestionsError,
    search,
    reset,
  }
}

/**
 * PromptArea component types
 *
 * A lightweight contentEditable-based text input that supports:
 * - Trigger characters (/, @, #) that activate handlers
 * - Immutable chips for resolved mentions/commands
 * - Configurable trigger behavior (dropdown vs callback)
 * - Simple inline markdown rendering
 */

/**
 * A segment of content within the editable text.
 * The document model is an ordered array of these segments.
 */
export type TextSegment = {
  type: 'text'
  text: string
}

export type ChipSegment = {
  type: 'chip'
  /** The trigger character that created this chip (e.g., '@', '#') */
  trigger: string
  /** The resolved value/ID (e.g., user ID, file ID) */
  value: string
  /** The display text shown in the chip */
  displayText: string
  /** Optional data payload attached to the chip */
  data?: unknown
  /**
   * True when this chip was auto-created by pressing space (resolveOnSpace).
   * Backspace on an auto-resolved chip reverts it to plain text instead of deleting.
   */
  autoResolved?: boolean
}

export type Segment = TextSegment | ChipSegment

/**
 * Determines where a trigger character is valid.
 * - 'start': Only valid at the very start of input or after a newline (e.g., slash commands)
 * - 'any': Valid after any whitespace boundary (e.g., @mentions)
 */
export type TriggerPosition = 'start' | 'any'

/**
 * Defines how a trigger behaves when activated.
 * - 'dropdown': Shows a popover with suggestions from `onSearch`
 * - 'callback': Fires `onActivate` immediately without a dropdown
 */
export type TriggerMode = 'dropdown' | 'callback'

/**
 * Visual style for rendered chips.
 * - 'pill': Button-like pill with background color, padding, border-radius (default)
 * - 'inline': Bold inline text that flows naturally with surrounding content
 */
export type ChipStyle = 'pill' | 'inline'

/**
 * A suggestion item shown in the trigger dropdown.
 */
export type TriggerSuggestion = {
  /** Unique value/ID for this suggestion */
  value: string
  /** Display label shown in the dropdown */
  label: string
  /** Optional description shown below the label */
  description?: string
  /** Optional icon element rendered before the label */
  icon?: React.ReactNode
  /** Optional arbitrary data passed through on selection */
  data?: unknown
}

/**
 * Configuration for a trigger character.
 */
export type TriggerConfig = {
  /** The trigger character (e.g., '/', '@', '#') */
  char: string
  /** Where this trigger is valid */
  position: TriggerPosition
  /** How this trigger behaves */
  mode: TriggerMode
  /**
   * For 'dropdown' mode: called with the current query to fetch suggestions.
   * Should return a list of suggestions to display.
   *
   * Receives an options object with an `AbortSignal` that is aborted when a
   * newer search supersedes this one. Pass it to `fetch()` or other async
   * APIs to cancel in-flight work automatically.
   */
  onSearch?: (
    query: string,
    options: { signal: AbortSignal },
  ) => TriggerSuggestion[] | Promise<TriggerSuggestion[]>
  /**
   * For 'dropdown' mode: called when a suggestion is selected.
   * Return the display text for the chip, or void to use `suggestion.label`.
   */
  onSelect?: (suggestion: TriggerSuggestion) => string | void
  /**
   * For 'callback' mode: called when the trigger is activated.
   * Receives the full input text and cursor position.
   */
  onActivate?: (context: TriggerActivateContext) => void
  /**
   * When true, pressing space while this trigger is active (with a non-empty query)
   * auto-resolves the typed text into a chip without selecting from the dropdown.
   * The auto-resolved chip can be reverted to plain text with backspace.
   * Useful for free-form tags (e.g., #hashtag).
   */
  resolveOnSpace?: boolean
  /**
   * Visual style for chips created by this trigger.
   * - 'pill' (default): Button-like pill with background, padding, border-radius
   * - 'inline': Bold inline text without pill styling
   */
  chipStyle?: ChipStyle
  /** CSS class name(s) applied to chips created by this trigger */
  chipClassName?: string
  /** Label used for accessibility (e.g., "mention", "command") */
  accessibilityLabel?: string
  /**
   * Debounce delay in milliseconds before calling `onSearch`.
   * Defaults to 0 (immediate). The initial empty-query search always fires
   * immediately regardless of this setting so the dropdown appears instantly.
   */
  searchDebounceMs?: number
  /**
   * Called when `onSearch` rejects or throws (non-abort errors only).
   * Use this to log errors or show toast notifications.
   */
  onSearchError?: (error: unknown) => void
  /**
   * Message shown in the dropdown when `onSearch` returns an empty array.
   * If omitted, the popover hides when there are no results (current behavior).
   */
  emptyMessage?: string
}

/**
 * Context passed to callback-mode trigger handlers.
 */
export type TriggerActivateContext = {
  /** The full plain text content at the time of activation */
  text: string
  /** The cursor offset position */
  cursorPosition: number
  /** Function to insert a chip at the current cursor position */
  insertChip: (chip: Omit<ChipSegment, 'type'>) => void
}

/**
 * Represents an active trigger being typed by the user.
 */
export type ActiveTrigger = {
  /** The trigger config that was activated */
  config: TriggerConfig
  /** Position (character offset) where the trigger character was typed */
  startOffset: number
  /** The text typed after the trigger character so far */
  query: string
}

/**
 * An image attachment displayed in the prompt area.
 * State is managed externally by the parent component.
 */
export type PromptAreaImage = {
  /** Unique identifier for this image */
  id: string
  /** URL to display (CDN URL or temporary blob URL for preview) */
  url: string
  /** Optional alt text for accessibility */
  alt?: string
  /** When true, shows a loading indicator over the thumbnail */
  loading?: boolean
}

/**
 * A file attachment displayed in the prompt area.
 * State is managed externally by the parent component.
 */
export type PromptAreaFile = {
  /** Unique identifier for this file */
  id: string
  /** Display filename (e.g., "report.pdf") */
  name: string
  /** File size in bytes */
  size?: number
  /** MIME type (used for icon selection, e.g., "application/pdf") */
  type?: string
  /** When true, shows a loading indicator over the file card */
  loading?: boolean
}

/**
 * Props for the PromptArea component.
 */
export type PromptAreaProps = {
  /** The document segments (controlled) */
  value: Segment[]
  /** Called when the content changes */
  onChange: (segments: Segment[]) => void
  /** Trigger configurations */
  triggers?: TriggerConfig[]
  /** Placeholder text when empty. Pass an array of strings to animate between them. */
  placeholder?: string | string[]
  /** Additional CSS class for the container */
  className?: string
  /** Whether the input is disabled */
  disabled?: boolean
  /** Whether to render simple inline markdown (bold, italic, URLs, lists) */
  markdown?: boolean
  /** Called when Enter is pressed (without Shift) */
  onSubmit?: (segments: Segment[]) => void
  /** Called when Escape is pressed */
  onEscape?: () => void
  /** Called when a chip element is clicked. Receives the chip's segment data. */
  onChipClick?: (chip: ChipSegment) => void
  /** Called when a new chip is added (dropdown selection, auto-resolve, paste, or imperative insert) */
  onChipAdd?: (chip: ChipSegment) => void
  /** Called when a chip is deleted (backspace or forward delete) */
  onChipDelete?: (chip: ChipSegment) => void
  /** Called when a URL link is clicked. Receives the URL string. */
  onLinkClick?: (url: string) => void
  /** Called after content is pasted. Receives the resulting segments and the paste source. */
  onPaste?: (data: { segments: Segment[]; source: 'internal' | 'external' }) => void
  /** Called after an undo operation. Receives the restored segments. */
  onUndo?: (segments: Segment[]) => void
  /** Called after a redo operation. Receives the restored segments. */
  onRedo?: (segments: Segment[]) => void
  /** Minimum height in pixels */
  minHeight?: number
  /** Maximum height in pixels */
  maxHeight?: number
  /** Auto-focus on mount */
  autoFocus?: boolean
  /** When true, the area auto-grows to fit content on focus and shrinks on blur */
  autoGrow?: boolean
  /** Accessible label for the input */
  'aria-label'?: string
  /** data-test-id for e2e testing */
  'data-test-id'?: string
  /** Array of image attachments to display */
  images?: PromptAreaImage[]
  /** Where to render the image strip relative to the text area. Defaults to 'above'. */
  imagePosition?: 'above' | 'below'
  /** Called when the user pastes an image from clipboard. Receives the File object. */
  onImagePaste?: (file: File) => void
  /** Called when the user clicks the remove button on an image */
  onImageRemove?: (image: PromptAreaImage) => void
  /** Called when the user clicks an image thumbnail */
  onImageClick?: (image: PromptAreaImage) => void
  /** Array of file attachments to display */
  files?: PromptAreaFile[]
  /** Where to render the file strip relative to the text area. Defaults to 'above'. */
  filePosition?: 'above' | 'below'
  /** Called when the user clicks the remove button on a file */
  onFileRemove?: (file: PromptAreaFile) => void
  /** Called when the user clicks a file attachment */
  onFileClick?: (file: PromptAreaFile) => void
}

/**
 * Ref handle exposed by PromptArea via useImperativeHandle.
 */
export type PromptAreaHandle = {
  /** Focus the editable area */
  focus: () => void
  /** Blur the editable area */
  blur: () => void
  /** Insert a chip at the current cursor position */
  insertChip: (chip: Omit<ChipSegment, 'type'>) => void
  /** Get the current plain text (without chip markup) */
  getPlainText: () => string
  /** Clear all content */
  clear: () => void
}
